      let _inlogLogoEditorWired = false;
      function wireInlogLogoEditorIfNeeded() {
        if (_inlogLogoEditorWired) return;
        _inlogLogoEditorWired = true;
        function wireLogoUpload(btnId, fileId, urlId, previewWraId, previewId, statusId) {
          const btn = document.getElementById(btnId);
          const file = document.getElementById(fileId);
          const urlEl = document.getElementById(urlId);
          const previewWrap = document.getElementById(previewWraId);
          const previewEl = document.getElementById(previewId);
          const statusEl = document.getElementById(statusId);
          const removeId = btnId.replace("UploadBtn", "RemoveBtn");
          const removeBtn = document.getElementById(removeId);
          if (!btn || !file) return;
          btn.addEventListener("click", () => file.click());
          file.addEventListener("change", async () => {
            const f = file.files && file.files[0];
            if (!f) return;
            // нҢҢмқј м„ нғқ мҰүмӢң dirty л§ҲнӮ№ вҖ” нҸ¬м»ӨмҠӨ ліөк·Җ мӢң soft pullмқҙ кө¬лІ„м „ лҚ°мқҙн„°лЎң
            // м—җл””н„°лҘј лҚ®м–ҙм“°лҠ” кІғмқ„ м°ЁлӢЁ
            markInlogEditorDirty();
            const localUrl = URL.createObjectURL(f);
            if (previewEl) previewEl.src = localUrl;
            if (previewWrap) previewWrap.style.display = "block";
            if (statusEl) { statusEl.textContent = "м—…лЎңл“ң мӨ‘вҖҰ"; statusEl.style.color = ""; }
            btn.disabled = true;
            try {
              const url = await uploadInlogHomeImageFileToSupabase(f);
              URL.revokeObjectURL(localUrl);
              if (urlEl) urlEl.value = url;
              if (previewEl) previewEl.src = url;
              if (statusEl) { statusEl.textContent = "вң“ м—…лЎңл“ң мҷ„лЈҢ В· м ҖмһҘ мӨ‘вҖҰ"; statusEl.style.color = "green"; }
              markInlogEditorDirty();
              // м—…лЎңл“ң мҷ„лЈҢ мҰүмӢң memoryStoreм—җ м ҖмһҘ вҶ’ pull/hydrate л°ңмғқ мӢң мғҲ URL ліҙмЎҙ
              writeInlogLogo(collectInlogLogoEditorPayload());
              // мһҗлҸҷмңјлЎң Supabaseм—җлҸ„ push (м ҖмһҘ лІ„нҠј м—ҶмқҙлҸ„ л°ҳмҳҒ)
              try {
                const ok = await forceClientKvPushWhenReady(true);
                if (ok) {
                  if (statusEl) { statusEl.textContent = "вң“ л“ұлЎқ мҷ„лЈҢ"; statusEl.style.color = "green"; }
                  clearInlogEditorDirty();
                } else {
                  if (statusEl) { statusEl.textContent = "вң“ м—…лЎңл“ң мҷ„лЈҢ (м ҖмһҘ лІ„нҠјмңјлЎң мөңмў… м ҖмһҘ)"; statusEl.style.color = "green"; }
                }
              } catch (_) {}
              setTimeout(() => { if (statusEl) { statusEl.textContent = ""; } }, 3000);
            } catch (e) {
              URL.revokeObjectURL(localUrl);
              if (statusEl) { statusEl.textContent = "вң— " + String(e.message || e); statusEl.style.color = "red"; }
              alert("мқҙлҜём§Җ м—…лЎңл“ң мӢӨнҢЁ:\n" + String(e.message || e));
            } finally {
              btn.disabled = false;
              file.value = "";
            }
          });
          if (removeBtn) {
            removeBtn.addEventListener("click", () => {
              if (urlEl) urlEl.value = "";
              if (previewEl) previewEl.src = "";
              if (previewWrap) previewWrap.style.display = "none";
              markInlogEditorDirty();
            });
          }
        }
        wireLogoUpload("inlogLogoHeaderUploadBtn", "inlogLogoHeaderFileInput", "inlogLogoHeaderUrl",
          "inlogLogoHeaderPreviewWrap", "inlogLogoHeaderPreview", "inlogLogoHeaderStatus");
        wireLogoUpload("inlogLogoFooterUploadBtn", "inlogLogoFooterFileInput", "inlogLogoFooterUrl",
          "inlogLogoFooterPreviewWrap", "inlogLogoFooterPreview", "inlogLogoFooterStatus");
      }
