            setSyncStatus(`лҢҖмӢңліҙл“ң(2В·3лІҲ) м ҖмһҘ мӢӨнҢЁ (${response.status}) вҖ” н…Ңмқҙлё”В·RLSВ·completed_history м»¬лҹј нҷ•мқё`, "error");
