          const remoteEmergencyMap = normalizeEmergencyLimitAdditions(remoteConfig.emergencyLimitAdditions);
          const sameEmergencyMap = JSON.stringify(localEmergencyMap) === JSON.stringify(remoteEmergencyMap);
          if (
            localConfig.weekdayLimit === remoteConfig.weekdayLimit &&
            localConfig.holidayLimit === remoteConfig.holidayLimit &&
            sameEmergencyMap
          ) {
            return false;
          }
          // emergencyLimitAdditionsлҘј STORAGE_LIMIT_CONFIGм—җ н•Ёк»ҳ нҸ¬н•Ён•ҳм—¬ кі к°қ нҺҳмқҙм§Җм—җм„ңлҸ„ мқҪмқ„ мҲҳ мһҲкІҢ н•Ё
          const sanitized = sanitizeLimitConfig(remoteConfig);
          originalSetItem(STORAGE_LIMIT_CONFIG, JSON.stringify({ ...sanitized, emergencyLimitAdditions: remoteEmergencyMap }));
          originalSetItem(STORAGE_DAILY_LIMITS, JSON.stringify({}));
          originalSetItem(STORAGE_EMERGENCY_LIMIT_ADDITIONS, JSON.stringify(remoteEmergencyMap));
