          await waitForSupabaseSyncPipelineIdle();
          setSyncStatus("лҸҷкё°нҷ”: м—…мІҙВ·кі к°қВ·мһ‘к°Җ л¶Ҳлҹ¬мҳӨлҠ” мӨ‘вҖҰ", "warn", { pinMs: 120000, force: true });
          await pullAdminCompaniesFromSupabaseAndRefresh();
