      async function mergeCompanyDirectoryRowsIntoCustomersStorageIncremental(rawRows) {
        const normalized = normalizeCustomerRows(Array.isArray(rawRows) ? rawRows : []);
        if (!normalized.length) return;
        const existing = readStorageArray(STORAGE_CUSTOMERS);
        const byLogin = new Map();
        existing.forEach((row) => {
          const k = String(row?.id || "").trim().toLowerCase();
          if (k) byLogin.set(k, { ...row });
        });
        normalized.forEach((row) => {
          const k = String(row?.id || "").trim().toLowerCase();
          if (!k) return;
          const prev = byLogin.get(k) || {};
          byLogin.set(k, { ...prev, ...row });
        });
        originalSetItem(STORAGE_CUSTOMERS, JSON.stringify([...byLogin.values()]));
      }

      async function fetchCompanyDirectoryForModalAndMergeCustomers(companyCode, companyName) {
        if (!USE_SUPABASE_SYNC || !SUPABASE_URL || !SUPABASE_ANON_KEY) return [];
        const code = normalizeCompanyCode(companyCode);
        const name = normalizeCompanyName(companyName);
        const hdr = {
          apikey: SUPABASE_ANON_KEY,
          Authorization: `Bearer ${SUPABASE_ANON_KEY}`
        };
        const select =
          "login_id,password,name,code,customer_phone,site_type,created_at,id";
        const acc = [];
        const pkSeen = new Set();

        function rememberRow(row) {
          const pk =
            String(row?.id ?? "")
              .trim()
              .toLowerCase() ||
            `lid:${String(row?.login_id || "")
              .trim()
              .toLowerCase()}`;
          if (!pk || pk === "lid:") return;
          if (pkSeen.has(pk)) return;
          pkSeen.add(pk);
          acc.push(row);
        }

        async function fetchByField(fieldName, fieldValue) {
          if (!fieldValue) return;
          const url = `${SUPABASE_URL}/rest/v1/${SUPABASE_COMPANY_DIRECTORY_TABLE}?select=${encodeURIComponent(
            select
          )}&${fieldName}=eq.${encodeURIComponent(fieldValue)}`;
          try {
            const response = await fetch(url, {
              method: "GET",
              headers: hdr,
              cache: "no-store"
            });
            if (!response.ok) return;
            const json = await response.json();
            if (!Array.isArray(json)) return;
            json.forEach(rememberRow);
          } catch (error) {
            console.warn("[нҡҢмӮ¬лӘЁлӢ¬] company_directory мЎ°нҡҢ мӢӨнҢЁ", fieldName, error);
          }
        }

        await fetchByField("code", code);
        await fetchByField("name", name);
        if (acc.length) await mergeCompanyDirectoryRowsIntoCustomersStorageIncremental(acc);
        try {
          await mergeMissingCompaniesFromCompanyDirectory();
        } catch (_) {}
        return acc;
      }

