      blogTaskListBodyEl?.addEventListener("click", (event) => {
        const btn = event.target?.closest?.("button[data-blog-act]");
        if (!btn) return;
        const act = btn.getAttribute("data-blog-act") || "";
        if (act === "openFolder") {
          const comp = String(btn.getAttribute("data-company") || "").trim();
          const code = String(btn.getAttribute("data-company-code") || "").trim();
          if (!comp) {
            alert("м—…мІҙлӘ…мқ„ нҷ•мқён•  мҲҳ м—ҶмҠөлӢҲлӢӨ.");
            return;
          }
          // мҰүмӢң м—ҙкё° вҖ” лЎңм»¬ мәҗмӢң мҡ°м„ .
          const cached = getCompanyDeliveryFolderUrlFromLocal(comp, code);
          if (cached) {
            window.open(cached, "_blank", "noopener,noreferrer");
            return;
          }
          btn.disabled = true;
          void (async () => {
            try {
              const u = await fetchCompanyDeliveryFolderUrlFromDirectory(comp, code);
              if (!u) {
                alert(
                  `гҖҢ${comp}гҖҚ мқҳ лӮ©н’Ҳ нҸҙлҚ” л§ҒнҒ¬лҘј м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ.\nгҖҢм—…мІҙм •ліҙкҙҖлҰ¬гҖҚм—җм„ң гҖҢнҸҙлҚ” м—°кІ°гҖҚлЎң л§Ҳмқҙл°•мҠӨ нҸҙлҚ” мЈјмҶҢлҘј м ҖмһҘн•ң л’Ө лӢӨмӢң мӢңлҸ„н•ҙ мЈјм„ёмҡ”.`
                );
                return;
              }
              window.open(u, "_blank", "noopener,noreferrer");
            } finally {
              btn.disabled = false;
            }
          })();
          return;
        }
        const sk = btn.getAttribute("data-sk") || "";
        if (!sk) return;
        const row = findBlogTaskRowBySk(sk);
        if (!row) {
          alert("н•ҙлӢ№ мҠӨмјҖмӨ„мқ„ м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ. мғҲлЎңкі м№Ё нӣ„ лӢӨмӢң мӢңлҸ„н•ҙмЈјм„ёмҡ”.");
          renderBlogTaskList();
          return;
        }
        if (act === "send") {
          btn.disabled = true;
          void handleBlogSmsSendForSchedule(sk, row.item).finally(() => {
            btn.disabled = false;
          });
          return;
        }
        if (act === "markDoneNoSms") {
          const company = String(row.item?.company || "").trim() || "(м—…мІҙлӘ… м—ҶмқҢ)";
          if (!confirm(`гҖҢ${company}гҖҚ вҖ” л¬ёмһҗ м—Ҷмқҙ л°ңмҶЎмҷ„лЈҢлЎң н‘ңмӢңн• к№Ңмҡ”?\n(мқҙлҜё лӢӨлҘё л°©лІ•мңјлЎң мІҳлҰ¬лҗҗкұ°лӮҳ л°ңмҶЎ л¶Ҳн•„мҡ”н•ң кІҪмҡ°мҡ©. лҗҳлҸҢлҰ¬кё° к°ҖлҠҘ.)`)) return;
          btn.disabled = true;
          void markBlogSentForKey(sk, new Date().toISOString()).finally(() => {
            btn.disabled = false;
            renderBlogTaskList();
          });
          return;
        }
        if (act === "revert") {
          handleBlogSmsRevertForSchedule(sk, row.item);
          return;
        }
        if (act === "photoEditMarkDone") {
          const company = String(row.item?.company || "").trim() || "(м—…мІҙлӘ… м—ҶмқҢ)";
          const dateLbl = formatYmdToMdSlash(String(row.item?.date || row.date || ""));
          if (!confirm(`гҖҢ${company}гҖҚ ${dateLbl} вҖ” мӮ¬м§„нҺём§‘мқ„ мҷ„лЈҢмІҳлҰ¬н•ҳмӢңкІ мҠөлӢҲк№Ң?\n(лё”лЎңк·ё нғӯ н‘ңмӢңмҡ© мҲҳлҸҷ мҷ„лЈҢ н‘ңмӢң В· лҗҳлҸҢлҰ¬кё° к°ҖлҠҘ)`)) return;
          markBlogPhotoEditDoneForKey(sk, new Date().toISOString());
          renderBlogTaskList();
          return;
        }
        if (act === "photoEditRevert") {
          const company = String(row.item?.company || "").trim() || "(м—…мІҙлӘ… м—ҶмқҢ)";
          if (!confirm(`гҖҢ${company}гҖҚ вҖ” мӮ¬м§„нҺём§‘ мҲҳлҸҷ мҷ„лЈҢ н‘ңмӢңлҘј лҗҳлҸҢлҰҙк№Ңмҡ”?`)) return;
          unmarkBlogPhotoEditDoneForKey(sk);
          renderBlogTaskList();
          return;
        }
      });
