      companyFormEl.addEventListener("submit", async (event) => {
        event.preventDefault();
        const name = normalizeCompanyName(companyNameInputEl.value);
        const phone = companyPhoneInputEl.value.trim();
        const code = normalizeCompanyCode(companyCodeInputEl?.value);
        const accountId = normalizeCompanyName(companyAccountIdInputEl?.value || name);
        const accountPassword = String(companyAccountPasswordInputEl?.value || "").trim();
        const accountSiteType = normalizeCustomerSiteTypeForStorage(companyAccountSiteTypeSelectEl?.value);
        if (!name) return;
        if (!accountPassword) {
          alert("м—…мІҙ кі„м • л№„л°ҖлІҲнҳёлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.");
          return;
        }
        const duplicated = companies.some(
          (item) => normalizeCompanyName(item?.name).toLowerCase() === normalizeCompanyName(name).toLowerCase()
        );
        if (duplicated) {
          alert("мқҙлҜё л“ұлЎқлҗң м—…мІҙлӘ…мһ…лӢҲлӢӨ.");
          return;
        }
        if (code && companies.some((item) => normalizeCompanyCode(item?.code).toLowerCase() === code.toLowerCase())) {
          alert("мқҙлҜё мӮ¬мҡ© мӨ‘мқё м—…мІҙ кі мң лІҲнҳёмһ…лӢҲлӢӨ.");
          return;
        }
        const users = readStorageArray(STORAGE_CUSTOMERS);
        const duplicateAccount = users.some((user) => String(user?.id || "").trim().toLowerCase() === accountId.toLowerCase());
        if (duplicateAccount) {
          alert("мқҙлҜё мӮ¬мҡ© мӨ‘мқё м—…мІҙ кі„м • м•„мқҙл””мһ…лӢҲлӢӨ.");
          return;
        }
        const newCompanyRow = { name, phone, code, siteType: accountSiteType };
        if (accountSiteType === "shopick") {
          const f = normalizeShopickServiceFlags(true, true, false);
          newCompanyRow.shopickPhoto = f.photo;
          newCompanyRow.shopickVideo = f.video;
          newCompanyRow.shopickBlog = f.blog;
        }
        companies.unshift(newCompanyRow);
        saveAdminCompaniesToStorage();
        users.unshift({
          id: accountId,
          password: accountPassword,
          company: name,
          companyCode: code,
          siteType: accountSiteType,
          phone: phone || "-",
          createdAt: new Date().toISOString()
        });
        localStorage.setItem(STORAGE_CUSTOMERS, JSON.stringify(users));
        const companyRegisterReceipt = {
          receiptId: `rcpt-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
          scheduleId: `company-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
          customerId: "",
          company: name,
          date: "",
          time: "",
          place: phone ? `м—…мІҙл“ұлЎқ / м—°лқҪмІҳ ${phone}` : "м—…мІҙл“ұлЎқ",
          source: "admin_company_create",
          createdAt: new Date().toISOString()
        };
        appendScheduleReceiptLedgerLocal(companyRegisterReceipt);
        void appendScheduleReceiptLedgerToSupabase(companyRegisterReceipt).catch((error) => {
          console.error("[SUBMISSION_RECEIPT][index] м—…мІҙл“ұлЎқ кё°лЎқ м ҖмһҘ мӢӨнҢЁ", error);
        });
        companyFormEl.reset();
        if (companyAccountIdInputEl) companyAccountIdInputEl.value = "";
        if (companyAccountSiteTypeSelectEl) companyAccountSiteTypeSelectEl.value = "inlog";
        companyRegisterPanelEl.classList.add("hidden");
        renderCompanies();
        if (USE_SUPABASE_SYNC) {
          try {
            await saveSingleCustomerAccountToSupabase({
              loginId: accountId,
              password: accountPassword,
              companyName: name,
              companyCode: code,
              phone: phone || "-",
              siteType: accountSiteType
            });
          } catch (error) {
            console.error("[CUSTOMERS][index] м—…мІҙл“ұлЎқ кі„м • мғқм„ұ лҸҷкё°нҷ” мӢӨнҢЁ", error);
            alert(`м—…мІҙ л“ұлЎқмқҖ мҷ„лЈҢлҗҳм—Ҳм§Җл§Ң кі„м • м„ңлІ„ лҸҷкё°нҷ”м—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ.\n${error?.message || "мһ мӢң нӣ„ м—…мІҙ кі„м • кҙҖлҰ¬м—җм„ң лӢӨмӢң м ҖмһҘн•ҙмЈјм„ёмҡ”."}`);
          }
        }
      });

      couponFormEl.addEventListener("submit", async (event) => {
        event.preventDefault();
        const success = await registerCouponPass(couponCompanyInputEl.value, couponCountSelectEl.value);
        if (!success) return;
        couponFormEl.reset();
        couponCountSelectEl.value = "1";
      });
      couponCompanySearchInputEl?.addEventListener("input", () => {
        couponCompanyKeyword = String(couponCompanySearchInputEl.value || "").trim();
        renderCouponPassList();
      });
      clearCouponCompanySearchBtnEl?.addEventListener("click", () => {
        couponCompanyKeyword = "";
        if (couponCompanySearchInputEl) couponCompanySearchInputEl.value = "";
        renderCouponPassList();
      });
      paymentCouponFormEl?.addEventListener("submit", async (event) => {
        event.preventDefault();
        const success = await registerCouponPass(paymentCouponCompanyInputEl?.value || "", paymentCouponCountSelectEl?.value || "1");
        if (!success) return;
        paymentCouponFormEl.reset();
        if (paymentCouponCountSelectEl) paymentCouponCountSelectEl.value = "1";
      });
      paymentCouponEditBtnEl?.addEventListener("click", async () => {
        const companyName = normalizeCompanyName(paymentCouponCompanyInputEl?.value || "");
        if (!companyName) {
          alert("м—…мІҙлӘ…мқ„ лЁјм Җ мһ…л Ҙн•ҙмЈјм„ёмҡ”.");
          return;
        }
        const couponRow = companies.find((c) => normalizeCompanyName(c?.name).toLowerCase() === companyName.toLowerCase());
        const currentRemaining = getCouponRemaining(companyName, normalizeCompanyCode(couponRow?.code));
        const nextRaw = prompt("ліҖкІҪн•  лӮЁмқҖ мҝ нҸ° нҡҹмҲҳлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.", String(currentRemaining));
        if (nextRaw === null) return;
        const success = await updateCouponPass(companyName, nextRaw);
        if (!success) return;
        alert(`${companyName} м—…мІҙ мҝ нҸ°мқҙ ${Math.floor(Number(nextRaw) || 0)}нҡҢлЎң мҲҳм •лҗҳм—ҲмҠөлӢҲлӢӨ.`);
      });

      couponListBodyEl.addEventListener("click", async (event) => {
        const actionButton = event.target.closest("button[data-action]");
        if (!actionButton) return;
        const action = String(actionButton.dataset.action || "");
        if (action === "startCouponEdit") {
          editingCouponCompany = normalizeCompanyName(actionButton.dataset.companyName);
          renderCouponPassList();
          return;
        }
        if (action === "cancelCouponEdit") {
          editingCouponCompany = "";
          renderCouponPassList();
          return;
        }
        if (action === "saveCouponPass") {
          const companyName = normalizeCompanyName(actionButton.dataset.companyName);
          if (!companyName) return;
          const rowEl = actionButton.closest("tr");
          const inputEl = rowEl?.querySelector(".coupon-remaining-input");
          const nextValue = inputEl?.value;
          const success = await updateCouponPass(companyName, nextValue);
          if (!success) return;
          editingCouponCompany = "";
          renderCouponPassList();
          return;
        }
        const button = event.target.closest("button[data-action='cancelCouponPass'][data-company-name]");
        if (!button) return;
        const companyName = normalizeCompanyName(button.dataset.companyName);
        if (!companyName) return;
        const couponRow = companies.find((c) => normalizeCompanyName(c?.name).toLowerCase() === companyName.toLowerCase());
        const couponCode = normalizeCompanyCode(couponRow?.code);
        const id = resolveCanonicalCompanyIdentity(companyName, couponCode);
        const primary = normalizeCompanyName(id.company);
        const legacy = normalizeCompanyName(companyName);
        const hasCoupon =
          (primary && Object.prototype.hasOwnProperty.call(couponPasses, primary)) ||
          (legacy && Object.prototype.hasOwnProperty.call(couponPasses, legacy));
        if (!hasCoupon) return;
        const confirmed = confirm(`${companyName} нҡҢм°Ёк¶Ң л“ұлЎқмқ„ м·ЁмҶҢн• к№Ңмҡ”?`);
        if (!confirmed) return;
        if (primary) delete couponPasses[primary];
        if (legacy) delete couponPasses[legacy];
        stripCouponAliasKeysForPrimary(primary, id.companyCode);
        editingCouponCompany = "";
        renderCouponPassList();
        renderPaymentList();
      });
      couponLowCountBoxEl?.addEventListener("click", (event) => {
        const button = event.target.closest("button[data-action='excludeLowCouponCompany'][data-company-name]");
        if (!button) return;
        const companyName = normalizeCompanyName(button.dataset.companyName);
        if (!companyName) return;
        const excludedSet = getCouponLowlistExcludedSet();
        excludedSet.add(companyName);
        saveCouponLowlistExcludedSet(excludedSet);
        renderCouponPassList();
      });

      transferToolEl?.addEventListener("click", (event) => {
        const sourceSearchBtn = event.target.closest("#transferSourceSearchBtn");
        if (sourceSearchBtn) {
          transferSourceKeyword = String(transferToolEl.querySelector("#transferSourceSearchInput")?.value || "").trim();
          renderTransferTool();
          return;
        }
        const targetSearchBtn = event.target.closest("#transferTargetSearchBtn");
        if (targetSearchBtn) {
          transferTargetKeyword = String(transferToolEl.querySelector("#transferTargetSearchInput")?.value || "").trim();
          renderTransferTool();
          return;
        }
        const sourcePickBtn = event.target.closest("button[data-action='pickTransferSource'][data-company-key]");
        if (sourcePickBtn) {
          transferSourceCompanyKey = String(sourcePickBtn.dataset.companyKey || "");
          renderTransferTool();
          return;
        }
        const targetPickBtn = event.target.closest("button[data-action='pickTransferTarget'][data-company-key]");
        if (targetPickBtn) {
          transferTargetCompanyKey = String(targetPickBtn.dataset.companyKey || "");
          renderTransferTool();
          return;
        }
        const runTransferBtn = event.target.closest("#runTransferBtn");
        if (runTransferBtn) {
          executeCompanyTransferByKeys(transferSourceCompanyKey, transferTargetCompanyKey);
        }
      });
      transferToolEl?.addEventListener("keydown", (event) => {
        if (event.key !== "Enter") return;
        const target = event.target;
        if (!(target instanceof HTMLInputElement)) return;
        if (target.id === "transferSourceSearchInput") {
          event.preventDefault();
          transferSourceKeyword = String(target.value || "").trim();
          renderTransferTool();
          return;
        }
        if (target.id === "transferTargetSearchInput") {
          event.preventDefault();
          transferTargetKeyword = String(target.value || "").trim();
          renderTransferTool();
        }
      });

      companyListEl.addEventListener("click", (event) => {
        const button = event.target.closest("button[data-action][data-company-index]");
        if (!button) return;
        const action = button.dataset.action;

        const index = Number(button.dataset.companyIndex);
        if (Number.isNaN(index) || !companies[index]) return;

        if (action === "startCompanyPhoneEdit") {
          editingCompanyIndex = index;
          renderCompanies();
          return;
        }

        if (action === "cancelCompanyPhone") {
          editingCompanyIndex = null;
          renderCompanies();
          return;
        }

        if (action === "saveCompanyInfo") {
          const itemEl = button.closest(".company-item");
          const nameInputEl = itemEl?.querySelector(".edit-company-name");
          const phoneInputEl = itemEl?.querySelector(".edit-company-phone");
          const codeInputEl = itemEl?.querySelector(".edit-company-code");
          const defaultMemoInputEl = itemEl?.querySelector(".edit-company-default-memo");
          const oldName = normalizeCompanyName(companies[index].name);
          const oldCode = normalizeCompanyCode(companies[index].code);
          const newName = normalizeCompanyName(nameInputEl?.value);
          const newPhone = phoneInputEl?.value?.trim() || "";
          const newCode = normalizeCompanyCode(codeInputEl?.value);
          const newDefaultMemo = defaultMemoInputEl?.value?.trim() || "";
          const photoEl = itemEl?.querySelector(".edit-shopick-photo");
          const videoEl = itemEl?.querySelector(".edit-shopick-video");
          const blogEl = itemEl?.querySelector(".edit-shopick-blog");
          let nextShopickFlags = null;
          if (photoEl && videoEl && blogEl) {
            nextShopickFlags = normalizeShopickServiceFlags(photoEl.checked, videoEl.checked, blogEl.checked);
          }
          if (!newName) {
            alert("м—…мІҙлӘ…мқ„ мһ…л Ҙн•ҙмЈјм„ёмҡ”.");
            return;
          }
          const oldCodeNorm = normalizeCompanyCode(oldCode).toLowerCase();
          const willMergeWithSaveRow = (company, companyIndex) => {
            if (companyIndex === index) return true;
            const sameName = normalizeCompanyName(company?.name).toLowerCase() === oldName.toLowerCase();
            const sameCode = Boolean(oldCodeNorm) && normalizeCompanyCode(company?.code).toLowerCase() === oldCodeNorm;
            return sameName || sameCode;
          };
          const duplicate = companies.some((company, companyIndex) => {
            if (willMergeWithSaveRow(company, companyIndex)) return false;
            return normalizeCompanyName(company.name).toLowerCase() === newName.toLowerCase();
          });
          if (duplicate) {
            alert("мқҙлҜё л“ұлЎқлҗң м—…мІҙлӘ…мһ…лӢҲлӢӨ.");
            return;
          }
          const couponNamesToMerge = new Set();
          companies.forEach((company) => {
            const sameName = normalizeCompanyName(company?.name).toLowerCase() === oldName.toLowerCase();
            const sameCode = Boolean(oldCodeNorm) && normalizeCompanyCode(company?.code).toLowerCase() === oldCodeNorm;
            if (!sameName && !sameCode) return;
            couponNamesToMerge.add(normalizeCompanyName(company.name));
            company.name = newName;
            company.phone = newPhone;
            company.code = newCode;
            company.defaultMemo = newDefaultMemo;
          });
          if (nextShopickFlags) {
            const nameKeyLower = normalizeCompanyName(newName).toLowerCase();
            const customersSnap = readStorageArray(STORAGE_CUSTOMERS);
            companies.forEach((c) => {
              if (normalizeCompanyName(c?.name).toLowerCase() !== nameKeyLower) return;
              const rowSt = normalizeCompanySiteTypeField(c?.siteType);
              const gk = getCompanyGroupKey(c.name, c.code);
              const matchedUser = customersSnap.find((u) => getCompanyGroupKey(u?.company, u?.companyCode) === gk);
              const userSt = matchedUser ? normalizeCustomerSiteTypeForStorage(matchedUser.siteType) : "inlog";
              if (rowSt === "shopick" || userSt === "shopick") {
                c.shopickPhoto = nextShopickFlags.photo;
                c.shopickVideo = nextShopickFlags.video;
                c.shopickBlog = nextShopickFlags.blog;
              }
            });
          }
          setCompanyDefaultMemoByName(newName, newDefaultMemo, newCode);
          syncMasterAccountMapForCompanyIdentity(newName, oldCode, newCode, oldName);
          const oldGroupKey = getCompanyGroupKey(oldName, oldCode);
          const nextGroupKey = getCompanyGroupKey(newName, newCode);

          if (oldName && oldName !== newName) {
            const matchScheduleForRename = (item) =>
              getCompanyGroupKey(item?.company, item?.companyCode) === oldGroupKey ||
              normalizeCompanyName(item?.company).toLowerCase() === oldName.toLowerCase() ||
              (Boolean(oldCodeNorm) && normalizeCompanyCode(item?.companyCode).toLowerCase() === oldCodeNorm);
            const applyScheduleRename = (item) => {
              item.company = newName;
              item.companyCode = normalizeCompanyCode(newCode);
              markScheduleRowDirty(item, "company_rename");
            };
            data.forEach((item) => {
              if (matchScheduleForRename(item)) applyScheduleRename(item);
            });
            onHoldPayments.forEach((item) => {
              if (matchScheduleForRename(item)) applyScheduleRename(item);
            });
            refundPayments.forEach((item) => {
              if (matchScheduleForRename(item)) applyScheduleRename(item);
            });

            let couponMerged = 0;
            couponNamesToMerge.forEach((n) => {
              if (couponPasses[n] !== undefined) {
                couponMerged += Math.max(0, Number(couponPasses[n]) || 0);
                delete couponPasses[n];
              }
            });
            if (couponMerged > 0) {
              couponPasses[newName] = Math.max(0, Number(couponPasses[newName]) || 0) + couponMerged;
            }

            const customerCompanies = readStorageArray(STORAGE_CUSTOMER_COMPANIES);
            customerCompanies.forEach((company) => {
              const companyGroupKey = getCompanyGroupKey(company?.name, company?.companyCode || company?.code);
              if (
                companyGroupKey === oldGroupKey ||
                normalizeCompanyName(company.name) === oldName ||
                (Boolean(oldCodeNorm) && normalizeCompanyCode(company?.companyCode || company?.code).toLowerCase() === oldCodeNorm)
              ) {
                company.name = newName;
                if (newCode) company.companyCode = newCode;
                if (newPhone) company.phone = newPhone;
              }
            });
            localStorage.setItem(STORAGE_CUSTOMER_COMPANIES, JSON.stringify(customerCompanies));

            const customerSchedules = readStorageArray(STORAGE_CUSTOMER_SCHEDULES);
            customerSchedules.forEach((schedule) => {
              const sk = getCompanyGroupKey(schedule?.company, schedule?.companyCode);
              if (
                sk === oldGroupKey ||
                normalizeCompanyName(schedule.company) === oldName ||
                (Boolean(oldCodeNorm) && normalizeCompanyCode(schedule?.companyCode).toLowerCase() === oldCodeNorm)
              ) {
                schedule.company = newName;
                if (newCode) schedule.companyCode = newCode;
              }
            });
            localStorage.setItem(STORAGE_CUSTOMER_SCHEDULES, JSON.stringify(customerSchedules));

            const customerUsers = readStorageArray(STORAGE_CUSTOMERS);
            customerUsers.forEach((user) => {
              const userGroupKey = getCompanyGroupKey(user?.company, user?.companyCode);
              if (
                userGroupKey === oldGroupKey ||
                normalizeCompanyName(user.company) === oldName ||
                (Boolean(oldCodeNorm) && normalizeCompanyCode(user?.companyCode).toLowerCase() === oldCodeNorm)
              ) {
                user.company = newName;
                if (newCode) user.companyCode = newCode;
                if (newPhone) user.phone = newPhone;
              }
            });
            localStorage.setItem(STORAGE_CUSTOMERS, JSON.stringify(customerUsers));
            try {
              localStorage.setItem(STORAGE_ADMIN_SCHEDULES, JSON.stringify(data));
            } catch (_) {}
            syncWriterSchedulesStorage();
            queueSchedulesSyncWithRetry(true);
            queuePaymentsSyncWithRetry();
          }
          if (oldGroupKey !== nextGroupKey && nextGroupKey) {
            const customerCompanies = readStorageArray(STORAGE_CUSTOMER_COMPANIES);
            customerCompanies.forEach((company) => {
              const companyGroupKey = getCompanyGroupKey(company?.name, company?.companyCode || company?.code);
              if (companyGroupKey === oldGroupKey) company.companyCode = newCode;
            });
            localStorage.setItem(STORAGE_CUSTOMER_COMPANIES, JSON.stringify(customerCompanies));
            const customerSchedules = readStorageArray(STORAGE_CUSTOMER_SCHEDULES);
            customerSchedules.forEach((schedule) => {
              const scheduleGroupKey = getCompanyGroupKey(schedule?.company, schedule?.companyCode);
              if (scheduleGroupKey === oldGroupKey) schedule.companyCode = newCode;
            });
            localStorage.setItem(STORAGE_CUSTOMER_SCHEDULES, JSON.stringify(customerSchedules));
            const customerUsers = readStorageArray(STORAGE_CUSTOMERS);
            customerUsers.forEach((user) => {
              const userGroupKey = getCompanyGroupKey(user?.company, user?.companyCode);
              if (userGroupKey === oldGroupKey) user.companyCode = newCode;
            });
            localStorage.setItem(STORAGE_CUSTOMERS, JSON.stringify(customerUsers));
          }

          persistCouponPassesToDevice();
          mergeCouponPassesByCanonicalIdentity();
          editingCompanyIndex = null;
          saveAdminCompaniesToStorage();
          renderCompanies();
          renderList();
          renderCustomerStatsDashboard();
          renderCustomerUpdateNotices();
          renderCustomerAlertHistory();
        }

        if (action === "deleteCompanyInfo") {
          const targetName = normalizeCompanyName(companies[index]?.name);
          if (!targetName) return;
          const isCustomerRegisteredCompany = readStorageArray(STORAGE_CUSTOMER_COMPANIES).some(
            (item) => normalizeCompanyName(item?.name).toLowerCase() === targetName.toLowerCase()
          );
          if (isCustomerRegisteredCompany) {
            const password = String(prompt("кі к°қ л“ұлЎқ м—…мІҙ мӮӯм ң л№„л°ҖлІҲнҳёлҘј мһ…л Ҙн•ҳм„ёмҡ”.") || "").trim();
            if (password !== ADMIN_OVERRIDE_PASSWORD) {
              alert("л№„л°ҖлІҲнҳёк°Җ мҳ¬л°”лҘҙм§Җ м•Ҡм•„ мӮӯм ңн•  мҲҳ м—ҶмҠөлӢҲлӢӨ.");
              return;
            }
          }
          const confirmed = confirm(`${targetName} м—…мІҙлҘј лӘ©лЎқм—җм„ң мӮӯм ңн• к№Ңмҡ”?`);
          if (!confirmed) return;
          const deletedRowSnapshot = companies[index]
            ? { name: companies[index].name, code: companies[index].code }
            : null;
          for (let i = companies.length - 1; i >= 0; i -= 1) {
            if (normalizeCompanyName(companies[i]?.name).toLowerCase() === targetName.toLowerCase()) {
              companies.splice(i, 1);
            }
          }
          if (isCustomerRegisteredCompany) {
            const customerCompanies = readStorageArray(STORAGE_CUSTOMER_COMPANIES).filter(
              (item) => normalizeCompanyName(item?.name).toLowerCase() !== targetName.toLowerCase()
            );
            localStorage.setItem(STORAGE_CUSTOMER_COMPANIES, JSON.stringify(customerCompanies));
          }
          {
            const delId = resolveCanonicalCompanyIdentity(deletedRowSnapshot?.name, deletedRowSnapshot?.code);
            const deletedGk = getCompanyGroupKey(delId.company, delId.companyCode);
            const anySameGroupLeft =
              deletedGk &&
              companies.some((c) => {
                const r = resolveCanonicalCompanyIdentity(c?.name, c?.code);
                return getCompanyGroupKey(r.company, r.companyCode) === deletedGk;
              });
            if (!anySameGroupLeft) {
              const delPrimary = normalizeCompanyName(delId.company);
              if (delPrimary) delete couponPasses[delPrimary];
              stripCouponAliasKeysForPrimary(delPrimary, delId.companyCode);
            }
          }
          editingCompanyIndex = null;
          saveAdminCompaniesToStorage();
          renderCompanies();
          renderCouponPassList();
          renderList();
          return;
        }
      });

      companyListEl.addEventListener("change", (event) => {
        const t = event.target;
        if (!(t instanceof HTMLInputElement)) return;
        if (
          !t.classList.contains("edit-shopick-photo") &&
          !t.classList.contains("edit-shopick-video") &&
          !t.classList.contains("edit-shopick-blog")
        ) {
          return;
        }
        const wrap = t.closest(".shopick-service-row");
        if (!wrap) return;
        const preview = wrap.querySelector(".shopick-preview");
        const photo = wrap.querySelector(".edit-shopick-photo");
        const video = wrap.querySelector(".edit-shopick-video");
        const blog = wrap.querySelector(".edit-shopick-blog");
        if (!preview || !photo || !video || !blog) return;
        const flags = normalizeShopickServiceFlags(photo.checked, video.checked, blog.checked);
        preview.textContent = formatShopickCompositionLabel(flags);
      });

      companyListEl.addEventListener("click", (event) => {
        if (event.target.closest("button, input, select, textarea, label")) return;
        const itemEl = event.target.closest(".company-item[data-company-index]");
        if (!itemEl) return;
        if (itemEl.querySelector(".edit-company-name")) return;
        const index = Number(itemEl.dataset.companyIndex);
        if (Number.isNaN(index) || !companies[index]) return;
        renderCompanyOrderHistory(companies[index].name);
        companyOrderHistoryModalEl?.classList.remove("hidden");
      });

      if (addPhotographerBtn) {
        addPhotographerBtn.addEventListener("click", () => {
          registerPanelEl.classList.toggle("hidden");
          if (!registerPanelEl.classList.contains("hidden")) {
            newPhotographerNameEl.focus();
          }
        });
      }

      function addPhotographerFromInput() {
        const trimmedName = newPhotographerNameEl.value.trim();
        const trimmedPhone = newPhotographerPhoneEl.value.trim();
        const trimmedCarNumber = newPhotographerCarEl.value.trim();
        if (!trimmedName) return;
        if (photographers.includes(trimmedName)) {
          alert("мқҙлҜё л“ұлЎқлҗң мһ‘к°Җмһ…лӢҲлӢӨ.");
          return;
        }
        photographers.push(trimmedName);
        photographerPhones[trimmedName] = trimmedPhone;
        photographerCarNumbers[trimmedName] = trimmedCarNumber;
        setExcludedPhotographerNames(getExcludedPhotographerNames().filter((name) => name !== trimmedName));
        const writerRows = readStorageArray(STORAGE_WRITERS);
        const existingWriterIndex = writerRows.findIndex(
          (writer) => String(writer?.name || "").trim().toLowerCase() === trimmedName.toLowerCase()
        );
        if (existingWriterIndex >= 0) {
          writerRows[existingWriterIndex].name = trimmedName;
          writerRows[existingWriterIndex].phone = trimmedPhone;
          writerRows[existingWriterIndex].carNumber = trimmedCarNumber;
        } else {
          writerRows.push({
            name: trimmedName,
            id: "",
            password: "",
            phone: trimmedPhone,
            carNumber: trimmedCarNumber,
            isActive: true
          });
        }
        setWritersStorage(writerRows);
        newPhotographerNameEl.value = "";
        newPhotographerPhoneEl.value = "";
        newPhotographerCarEl.value = "";
        savePhotographerProfilesToStorage();
        renderPhotographers();
        renderList();
      }

      function excludePhotographerByName(name) {
        const removeIndex = photographers.findIndex((item) => item === name);
        if (removeIndex < 0) return;
        photographers.splice(removeIndex, 1);
        setExcludedPhotographerNames([...getExcludedPhotographerNames(), name]);

        const today = new Date();
        const todayKey = `${today.getFullYear()}-${String(today.getMonth() + 1).padStart(2, "0")}-${String(today.getDate()).padStart(2, "0")}`;
        data.forEach((item) => {
          const itemDate = String(item?.date || "").trim();
          if (item.name !== name) return;
          if (!/^\d{4}-\d{2}-\d{2}$/.test(itemDate)) return;
          if (itemDate < todayKey) return;
          item.name = "мһ‘к°ҖлҜём •";
          item.writerPhone = "";
          item.writerCarNumber = "";
        });

        savePhotographerProfilesToStorage();
        renderPhotographers();
        renderList();
      }

      function deletePhotographerByName(name) {
        const targetName = String(name || "").trim();
        if (!targetName) return;
        const activeIndex = photographers.findIndex((item) => item === targetName);
        if (activeIndex >= 0) {
          photographers.splice(activeIndex, 1);
        }
        setExcludedPhotographerNames(getExcludedPhotographerNames().filter((item) => item !== targetName));
        delete photographerPhones[targetName];
        delete photographerCarNumbers[targetName];

        data.forEach((item) => {
          if (item.name === targetName) {
            item.name = "мһ‘к°ҖлҜём •";
            item.writerPhone = "";
            item.writerCarNumber = "";
          }
        });

        const writers = readStorageArray(STORAGE_WRITERS).filter((writer) => String(writer?.name || "").trim() !== targetName);
        setWritersStorage(writers);

        if (currentPhotographerFilter === targetName) {
          currentPhotographerFilter = "all";
        }
        editingPhotographerName = null;
        savePhotographerProfilesToStorage();
        renderPhotographers();
        renderList();
      }

      function restoreExcludedPhotographerByName(name) {
        const targetName = String(name || "").trim();
        if (!targetName) return;
        const excludedNames = getExcludedPhotographerNames();
        if (!excludedNames.includes(targetName)) return;
        if (!photographers.includes(targetName)) {
          photographers.push(targetName);
        }
        setExcludedPhotographerNames(excludedNames.filter((item) => item !== targetName));
        savePhotographerProfilesToStorage();
        renderPhotographers();
        renderList();
      }

      function savePhotographerInfo(oldName, itemEl) {
        const index = photographers.findIndex((item) => item === oldName);
        if (index < 0 || !itemEl) return;
        const nameInputEl = itemEl.querySelector(".edit-photographer-name");
        const phoneInputEl = itemEl.querySelector(".edit-photographer-phone");
        const carInputEl = itemEl.querySelector(".edit-photographer-car");

        const newName = String(nameInputEl?.value || "").trim();
        const newPhone = String(phoneInputEl?.value || "").trim();
        const newCarNumber = String(carInputEl?.value || "").trim();

        if (!newName) {
          alert("мһ‘к°ҖлӘ…мқ„ мһ…л Ҙн•ҙмЈјм„ёмҡ”.");
          return;
        }
        const duplicate = photographers.some((name, rowIndex) => rowIndex !== index && name.toLowerCase() === newName.toLowerCase());
        if (duplicate) {
          alert("мқҙлҜё л“ұлЎқлҗң мһ‘к°ҖлӘ…мһ…лӢҲлӢӨ.");
          return;
        }

        photographers[index] = newName;
        delete photographerPhones[oldName];
        delete photographerCarNumbers[oldName];
        photographerPhones[newName] = newPhone;
        photographerCarNumbers[newName] = newCarNumber;
        setExcludedPhotographerNames(
          getExcludedPhotographerNames().map((name) => (name === oldName ? newName : name))
        );

        const writers = readStorageArray(STORAGE_WRITERS);
        const writerIndex = writers.findIndex((writer) => String(writer?.name || "").trim() === oldName);
        if (writerIndex >= 0) {
          writers[writerIndex].name = newName;
          if (newPhone) writers[writerIndex].phone = newPhone;
          if (newCarNumber) writers[writerIndex].carNumber = newCarNumber;
        } else {
          writers.push({
            name: newName,
            id: "",
            password: "",
            phone: newPhone,
            carNumber: newCarNumber,
            isActive: true
          });
        }
        setWritersStorage(writers);

        data.forEach((item) => {
          if (item.name !== oldName) return;
          item.name = newName;
          item.writerPhone = newPhone;
          item.writerCarNumber = newCarNumber;
          syncCustomerScheduleFromAdminEdit(item, item.time || "");
        });

        if (currentPhotographerFilter === oldName) {
          currentPhotographerFilter = newName;
        }
        editingPhotographerName = null;
        savePhotographerProfilesToStorage();
        renderPhotographers();
        renderList();
      }
      function saveWriterProfileFromHistory(oldName, newName, newPhone, newCarNumber) {
        const normalizedOld = String(oldName || "").trim();
        const normalizedNew = String(newName || "").trim();
        const nextPhone = String(newPhone || "").trim();
        const nextCarNumber = String(newCarNumber || "").trim();
        if (!normalizedOld || !normalizedNew) {
          alert("мһ‘к°ҖлӘ…мқ„ мһ…л Ҙн•ҙмЈјм„ёмҡ”.");
          return;
        }
        const oldLower = normalizedOld.toLowerCase();
        const newLower = normalizedNew.toLowerCase();
        const activeDuplicate = photographers.some((name) => String(name || "").trim().toLowerCase() === newLower && String(name || "").trim().toLowerCase() !== oldLower);
        const excludedNames = getExcludedPhotographerNames();
        const excludedDuplicate = excludedNames.some((name) => String(name || "").trim().toLowerCase() === newLower && String(name || "").trim().toLowerCase() !== oldLower);
        if (activeDuplicate || excludedDuplicate) {
          alert("мқҙлҜё л“ұлЎқлҗң мһ‘к°ҖлӘ…мһ…лӢҲлӢӨ.");
          return;
        }

        const activeIndex = photographers.findIndex((name) => String(name || "").trim().toLowerCase() === oldLower);
        if (activeIndex >= 0) {
          photographers[activeIndex] = normalizedNew;
        }
        delete photographerPhones[normalizedOld];
        delete photographerCarNumbers[normalizedOld];
        photographerPhones[normalizedNew] = nextPhone;
        photographerCarNumbers[normalizedNew] = nextCarNumber;
        setExcludedPhotographerNames(excludedNames.map((name) => (String(name || "").trim().toLowerCase() === oldLower ? normalizedNew : name)));

        const writers = readStorageArray(STORAGE_WRITERS);
        const writerIndex = writers.findIndex((writer) => String(writer?.name || "").trim().toLowerCase() === oldLower);
        if (writerIndex >= 0) {
          writers[writerIndex].name = normalizedNew;
          writers[writerIndex].phone = nextPhone;
          writers[writerIndex].carNumber = nextCarNumber;
        } else {
          writers.push({
            name: normalizedNew,
            id: "",
            password: "",
            phone: nextPhone,
            carNumber: nextCarNumber,
            isActive: true
          });
        }
        setWritersStorage(writers);

        const updateRow = (row) => {
          if (String(row?.name || "").trim().toLowerCase() !== oldLower) return;
          row.name = normalizedNew;
          row.writerPhone = nextPhone;
          row.writerCarNumber = nextCarNumber;
        };
        data.forEach((item) => {
          updateRow(item);
          syncCustomerScheduleFromAdminEdit(item, item.time || "");
        });
        onHoldPayments.forEach(updateRow);
        refundPayments.forEach(updateRow);

        if (currentPhotographerFilter.toLowerCase() === oldLower) {
          currentPhotographerFilter = normalizedNew;
        }
        savePhotographerProfilesToStorage();
        renderPhotographers();
        renderList();
        renderWriterHistory(normalizedNew);
        alert("мһ‘к°Җ м •ліҙк°Җ ліҖкІҪлҗҳм—ҲмҠөлӢҲлӢӨ.");
      }

      function saveInlineEdit(index, itemEl) {
        const item = data[index];
        if (!item || !itemEl) return;
        const previousTime = item.time || "";
        const previousDate = item.date || "";

        const date = itemEl.querySelector(".edit-date-only")?.value?.trim();
        const hour = itemEl.querySelector(".edit-hour")?.value;
        const minute = itemEl.querySelector(".edit-minute")?.value;
        const company = itemEl.querySelector(".edit-company")?.value?.trim();
        const place = itemEl.querySelector(".edit-place")?.value?.trim();
        const pyeong = itemEl.querySelector(".edit-pyeong")?.value?.trim();
        const jointCode = itemEl.querySelector(".edit-jointCode")?.value?.trim();
        const doorCode = itemEl.querySelector(".edit-doorCode")?.value?.trim();
        const memo = itemEl.querySelector(".edit-memo")?.value?.trim();
        const composition = itemEl.querySelector(".edit-composition")?.value;
        const name = itemEl.querySelector(".edit-name")?.value;
        const nextDate = date || item.date;
        if (nextDate !== item.date) {
          const countAtDate = getActiveScheduleCountByDate(nextDate, index);
          const dailyLimit = getEffectiveDailyLimit(nextDate);
          if (countAtDate >= dailyLimit) {
            // л§Ҳк°җлҗң лӮ м§ңлЎң мҳ®кё°лҠ” кІҪмҡ° вҖ” л¬ҙмЎ°кұҙ м°ЁлӢЁмқҙ м•„лӢҲлқј кҙҖлҰ¬мһҗ л№„л°ҖлІҲнҳёлЎңл§Ң к°•м ң н—Ҳмҡ©.
            // (мҙҲкіјмҳҲм•Ҫ л°©м§Җ + кјӯ н•„мҡ”н•  л•Ң кҙҖлҰ¬мһҗк°Җ мұ…мһ„м§Җкі  override)
            const pw = String(
              prompt(
                `${nextDate} мқҖ(лҠ”) мҳҲм•Ҫмқҙ кҪү м°јмҠөлӢҲлӢӨ (нҳ„мһ¬ ${countAtDate}кұҙ / мөңлҢҖ ${dailyLimit}кұҙ).\n` +
                  "к·ёлһҳлҸ„ мқҙ лӮ м§ңлЎң мҳ®кё°л Өл©ҙ кҙҖлҰ¬мһҗ л№„л°ҖлІҲнҳёлҘј мһ…л Ҙн•ҳм„ёмҡ”."
              ) || ""
            ).trim();
            if (pw !== ADMIN_OVERRIDE_PASSWORD) {
              alert("л№„л°ҖлІҲнҳёк°Җ мҳ¬л°”лҘҙм§Җ м•Ҡм•„ л§Ҳк°җлҗң лӮ м§ңлЎң мҳ®кёё мҲҳ м—ҶмҠөлӢҲлӢӨ.");
              return;
            }
            // л№„лІҲ мқјм№ҳ вҶ’ override н—Ҳмҡ© (м•„лһҳлЎң кі„мҶҚ м§„н–ү)
          }
        }

        if (date) item.date = date;
        if (hour && minute) {
          item.time = `${hour}:${minute}`;
          item.timePreference = "exact";
        }
        if (company) {
          const canonicalIdentity = resolveCanonicalCompanyIdentity(company, item?.companyCode);
          item.company = canonicalIdentity.company || company;
          item.companyCode = canonicalIdentity.companyCode || item.companyCode || "";
        }
        if (place) item.place = place;
        item.pyeong = pyeong || "";
        item.jointCode = jointCode || "";
        item.doorCode = doorCode || "";
        item.memo = memo || "";
        if (composition) item.composition = composition;
        if (name) {
          item.name = name;
          item.writerPhone = photographerPhones[name] || "";
          item.writerCarNumber = photographerCarNumbers[name] || "";
        }
        markScheduleRowDirty(item, "schedule_mutation");
        syncCustomerScheduleFromAdminEdit(item, previousTime, previousDate);

        editingIndex = null;
        renderList();
        // лӢ¬л Ҙ мқёлқјмқё мҲҳм •лҸ„ мҰүмӢң Supabaseм—җ push н•ҙм•ј мһ‘к°Җ нҺҳмқҙм§Җ(мӣҗкІ© schedules мЎ°нҡҢ)м—җм„ң ліҙмқёлӢӨ.
        try { localStorage.setItem(STORAGE_ADMIN_SCHEDULES, JSON.stringify(data)); } catch (_) {}
        ensureScheduleUuid(item);
        syncWriterSchedulesStorage();
        queueSchedulesSyncWithRetry(true);
        // queueSchedulesSyncлҠ” ліҖнҷ” л№„көҗ/н•„н„°лЎң лҲ„лқҪлҗ  мҲҳ мһҲм–ҙ, нҺём§‘н•ң н–үмқҖ м§Ғм ‘ PATCHлЎң н•ң лІҲ лҚ” ліҙмһҘн•ңлӢӨ.
        void directPatchScheduleFields(item);
      }

      function saveDateEdit(index, itemEl) {
        const item = data[index];
        if (!item || !itemEl) return;
        const previousTime = item.time || "";
        const previousDate = item.date || "";
        const hour = itemEl.querySelector(".edit-hour")?.value;
        const minute = itemEl.querySelector(".edit-minute")?.value;
        if (!hour || !minute) {
          alert("мӢңк°„кіј л¶„мқ„ м„ нғқн•ҙмЈјм„ёмҡ”.");
          return;
        }
        item.time = `${hour}:${minute}`;
        item.timePreference = "exact";
        markScheduleRowDirty(item, "schedule_mutation");
        syncCustomerScheduleFromAdminEdit(item, previousTime, previousDate);

        editingDateIndex = null;
        renderList();
        try { localStorage.setItem(STORAGE_ADMIN_SCHEDULES, JSON.stringify(data)); } catch (_) {}
        ensureScheduleUuid(item);
        syncWriterSchedulesStorage();
        queueSchedulesSyncWithRetry(true);
        void directPatchScheduleFields(item);
      }

      function deleteSchedule(index) {
        if (index < 0 || index >= data.length) return;
        const deletedItem = data[index];
        // мһ…кёҲмҷ„лЈҢ кұҙмқҖ мӮӯм ң лҢҖмӢ  гҖҢліҙлҘҳ м—…мІҙгҖҚлЎң мқҙкҙҖлҗҳлҜҖлЎң нҷ•мқё л¬ёкө¬лҘј лӢӨлҘҙкІҢ м•ҲлӮҙ.
        const isPaidRow = String(deletedItem?.paymentStatus || "").trim() === "мһ…кёҲмҷ„лЈҢ";
        const confirmed = confirm(
          isPaidRow
            ? "мһ…кёҲмҷ„лЈҢлҗң кұҙмһ…лӢҲлӢӨ. мҠӨмјҖмӨ„м—җм„ң л№јкі  гҖҢліҙлҘҳ м—…мІҙгҖҚлЎң мқҙлҸҷн• к№Ңмҡ”?\n(лҗҳлҸҢлҰ¬кё°В·нҷҳл¶Ҳ нӣ„мҶҚмІҳлҰ¬к°Җ к°ҖлҠҘн•©лӢҲлӢӨ)"
            : "мӮӯм ңн•ҳмӢңкІ мҠөлӢҲк№Ң?"
        );
        if (!confirmed) return;
        ensureScheduleUuid(deletedItem);
        const deletedScheduleId = String(deletedItem?.customerScheduleId || "").trim();
        const deletedDate = String(deletedItem?.date || "").trim();
        const deletedTime = String(deletedItem?.time || "").trim();
        const deletedCompany = normalizeCompanyName(deletedItem?.company);
        const deletedPlace = String(deletedItem?.place || "").trim();
        const isSameDeletedSchedule = (row) => {
          const rowScheduleId = String(row?.customerScheduleId || "").trim();
          if (deletedScheduleId && rowScheduleId === deletedScheduleId) return true;
          const sameDate = String(row?.date || "").trim() === deletedDate;
          const sameTime = String(row?.time || "").trim() === deletedTime;
          const samePlace = String(row?.place || "").trim() === deletedPlace;
          const sameCompany = normalizeCompanyName(row?.company) === deletedCompany;
          // нҡҢмӮ¬лӘ…мқҙ л§Өн•‘ ліҖкІҪлҗҳлҠ” кІҪмҡ°к°Җ мһҲм–ҙ мһҘмҶҢ+мқјмӢң кё°мӨҖлҸ„ н•Ёк»ҳ н—Ҳмҡ©
          return (sameDate && sameTime && samePlace && sameCompany) || (sameDate && sameTime && samePlace);
        };
        const shouldMoveToHoldAfterDelete = String(deletedItem?.paymentStatus || "").trim() === "мһ…кёҲмҷ„лЈҢ";

        // в”Җв”Җ мһ…кёҲмҷ„лЈҢ кұҙмқҖ гҖҢмӮӯм ңгҖҚк°Җ м•„лӢҲлқј гҖҢліҙлҘҳ м—…мІҙлЎң мқҙкҙҖгҖҚ в”Җв”Җ
        // м„ңлІ„ schedules row лҘј DELETE н•ҳкұ°лӮҳ tombstone/pendingDelete лҘј кұёл©ҙ лӢӨмқҢ pull мқҳ
        // н•„н„°(source="deleted" / schedulePendingDeletionIds)м—җ кұёл Ө ліҙлҘҳ н•ӯлӘ©мқҙ мӮ¬лқјм§„лӢӨ.
        // (= мӮ¬мҡ©мһҗк°Җ ліё "мһ…кёҲмІҳлҰ¬ нӣ„ мҠӨмјҖмӨ„ м·ЁмҶҢ мӢң ліҙлҘҳлЎң м•Ҳ к°Җкі  к·ёлғҘ мӮ¬лқјм§җ" лІ„к·ё)
        // вҶ’ row лҠ” мң м§Җн•ҳкі  source л§Ң "hold" лЎң PATCH н•ңлӢӨ. (мқҙнӣ„ лҗҳлҸҢлҰ¬кё°/нҷҳл¶Ҳ нӣ„мҶҚмІҳлҰ¬ к°ҖлҠҘ)
        if (shouldMoveToHoldAfterDelete) {
          data.splice(index, 1);
          for (let i = onHoldPayments.length - 1; i >= 0; i -= 1) {
            if (isSameDeletedSchedule(onHoldPayments[i])) onHoldPayments.splice(i, 1);
          }
          for (let i = refundPayments.length - 1; i >= 0; i -= 1) {
            if (isSameDeletedSchedule(refundPayments[i])) refundPayments.splice(i, 1);
          }
          const heldItem = { ...deletedItem, paymentStatus: "мһ…кёҲмҷ„лЈҢ", localUpdatedAt: new Date().toISOString() };
          onHoldPayments.unshift(heldItem);
          editingIndex = null;
          editingDateIndex = null;
          try { localStorage.setItem(STORAGE_ADMIN_SCHEDULES, JSON.stringify(data)); } catch (_) {}
          // freshness guard мҡ°нҡҢ вҖ” мЎ°мһ‘ м§Ғнӣ„ pull мқҙ мҳӣ мғҒнғңлЎң лҗҳлҸҢлҰ¬м§Җ м•ҠкІҢ
          try {
            const nowIso = new Date().toISOString();
            localStorage.setItem(STORAGE_LAST_PAYMENT_PULL_AT, nowIso);
            localStorage.setItem(STORAGE_LAST_SCHEDULE_PULL_AT, nowIso);
          } catch (_) {}
          markScheduleRowDirty(heldItem, "payment_mutation");
          renderList();
          renderPaymentList();
          queueSchedulesSyncWithRetry(true);
          queuePaymentsSyncWithRetry();
          // м„ңлІ„ schedules row мқҳ source лҘј "hold" лЎң PATCH (DELETE н•ҳм§Җ м•ҠмқҢ)
          if (deletedScheduleId) void directPatchScheduleSource(deletedScheduleId, "hold");
          return;
        }

        appendCanceledScheduleRecord(deletedItem, "admin", "кҙҖлҰ¬мһҗмӮӯм ң");
        data.splice(index, 1);
        for (let i = onHoldPayments.length - 1; i >= 0; i -= 1) {
          if (!isSameDeletedSchedule(onHoldPayments[i])) continue;
          onHoldPayments.splice(i, 1);
        }
        for (let i = refundPayments.length - 1; i >= 0; i -= 1) {
          if (isSameDeletedSchedule(refundPayments[i])) {
            refundPayments.splice(i, 1);
          }
        }

        // кі к°қ нҺҳмқҙм§Җм—җм„ң л„ҳм–ҙмҳЁ мқјм •мқҖ кі к°қ м ҖмһҘмҶҢм—җм„ңлҸ„ н•Ёк»ҳ мӮӯм ңн•ҙм•ј мһ¬л“ұмһҘн•ҳм§Җ м•ҠмқҢ
        const customerSchedules = readStorageArray(STORAGE_CUSTOMER_SCHEDULES);
        const nextCustomerSchedules = customerSchedules.filter((row) => !isSameDeletedSchedule(row));
        if (nextCustomerSchedules.length !== customerSchedules.length) {
          localStorage.setItem(STORAGE_CUSTOMER_SCHEDULES, JSON.stringify(nextCustomerSchedules));
        } else {
          // л§Ҳм§Җл§ү ліҙм •: м•„мқҙл”” кё°мӨҖл§Ң лі„лҸ„лЎң н•ң лІҲ лҚ” нҷ•мқё
          const customerIndex = deletedScheduleId
            ? customerSchedules.findIndex((row) => String(row?.customerScheduleId || "").trim() === deletedScheduleId)
            : -1;
          if (customerIndex >= 0) customerSchedules.splice(customerIndex, 1);
          localStorage.setItem(STORAGE_CUSTOMER_SCHEDULES, JSON.stringify(customerSchedules));
        }

        editingIndex = null;
        editingDateIndex = null;
        // STORAGE_ADMIN_SCHEDULES мҰүмӢң к°ұмӢ  вҖ” мғҲлЎңкі м№Ё мӢң мҠӨлғ…мғ·/memoryStoreм—җлҸ„ л°ҳмҳҒ
        try { localStorage.setItem(STORAGE_ADMIN_SCHEDULES, JSON.stringify(data)); } catch (_) {}
        // мӮӯм ң мҰүмӢң pull м°ЁлӢЁ мҝЁлӢӨмҡҙ 8мҙҲ вҖ” м„ңлІ„ DELETE мҷ„лЈҢ м „ pullлЎң ліөкө¬ л°©м§Җ
        scheduleSyncCooldownUntil = Date.now() + 8000;
        if (deletedScheduleId) addPendingDeleteId(deletedScheduleId);
        if (deletedScheduleId) addScheduleDeleteTombstoneId(deletedScheduleId);
        renderList();
        queueSchedulesSyncWithRetry(true);
        queuePaymentsSyncWithRetry();
        // м„ңлІ„ rowмқҳ sourceлҘј мҰүмӢң "deleted"лЎң PATCH вҶ’ pull мӢң н•„н„°лЎң мҷ„м „ м°ЁлӢЁ
        if (deletedScheduleId) void directPatchScheduleSource(deletedScheduleId, "deleted");
        const deleteReceipt = {
          receiptId: `rcpt-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
          scheduleId: String(deletedScheduleId || "").trim(),
          customerId: "",
          company: String(deletedItem?.company || "").trim(),
          date: String(deletedItem?.date || "").trim(),
          time: String(deletedItem?.time || "").trim(),
          place: String(deletedItem?.place || "").trim(),
          source: "admin_delete",
          createdAt: new Date().toISOString()
        };
        appendScheduleReceiptLedgerLocal(deleteReceipt);
        void appendScheduleReceiptLedgerToSupabase(deleteReceipt).catch((error) => {
          console.error("[SUBMISSION_RECEIPT][index] кҙҖлҰ¬мһҗ мӮӯм ңкё°лЎқ м ҖмһҘ мӢӨнҢЁ", error);
        });
        console.log(`[DELETE] мӮӯм ң мӢңлҸ„ вҖ” id="${deletedScheduleId}", company="${deletedItem?.company}", date="${deletedItem?.date}", time="${deletedItem?.time}"`);
        void deleteScheduleFromSupabaseByItem(deletedItem)
          .then((deleted) => {
            console.log(`[DELETE] м„ңлІ„ мӮӯм ң кІ°кіј: deleted=${deleted}, id="${deletedScheduleId}"`);
            if (deleted === true) {
              setSyncStatus("м„ңлІ„ мӮӯм ң мҷ„лЈҢ вң“", "ok", { pinMs: 3000 });
              // мӢӨм ң мӮӯм ң/нҢЁм№ҳ м„ұкіө нҷ•мқё нӣ„м—җл§Ң pendingId н•ҙм ң
              if (deletedScheduleId) removePendingDeleteId(deletedScheduleId);
            } else {
              // мӮӯм ңлҸ„ PATCHлҸ„ м•ҲлҗЁ вҖ” pendingId мң м§Җн•ҙм„ң pull н•„н„°лЎң кі„мҶҚ м°ЁлӢЁ
              console.error(`[DELETE] м„ңлІ„м—җм„ң мӮӯм ң мӢӨнҢЁ вҖ” pendingId мң м§Җ`);
              setSyncStatus("м„ңлІ„ мӮӯм ң мӢӨнҢЁ В· Supabase RLS м •мұ… нҷ•мқё н•„мҡ”", "error", { pinMs: 8000 });
              alert(`вҡ пёҸ м„ңлІ„м—җм„ң мҠӨмјҖмӨ„ мӮӯм ң л¶Ҳк°Җ\n\nSupabase вҶ’ SQL Editorм—җм„ң м•„лһҳлҘј мӢӨн–үн•ҙмЈјм„ёмҡ”:\n\nDROP POLICY IF EXISTS "public_delete_schedules" ON public.schedules;\nCREATE POLICY "public_delete_schedules" ON public.schedules FOR DELETE TO anon, authenticated USING (true);\n\nк·ёлҰ¬кі  UPDATE м •мұ…лҸ„ нҷ•мқён•ҳм„ёмҡ”.`);
            }
            scheduleSyncCooldownUntil = Math.max(scheduleSyncCooldownUntil, Date.now() + 800);
          })
          .catch((error) => {
            const errMsg = String(error?.message || "");
            console.error(`[DELETE] м„ңлІ„ мӮӯм ң мӢӨнҢЁ: ${errMsg}`);
            setSyncStatus(`м„ңлІ„ мӮӯм ң мӢӨнҢЁ: ${errMsg.slice(0, 60)}`, "error", { pinMs: 6000 });
            alert(`вҡ пёҸ мҠӨмјҖмӨ„ м„ңлІ„ мӮӯм ң мӢӨнҢЁ\n\nмҳӨлҘҳ: ${errMsg}`);
          });
        if (!shouldMoveToHoldAfterDelete) {
          void deleteRelatedPaymentsFromSupabaseBySchedule(deletedItem)
            .then((deleted) => {
              if (!deleted) return;
              return pullPaymentsFromSupabaseAndApply();
            })
            .catch((error) => {
              console.error("[PAYMENTS][index] м—°кҙҖ мһ…кёҲ мӮӯм ң мӢӨнҢЁ", error);
            });
        }
      }

      function buildScheduleFallbackKey(row) {
        return [
          String(row?.date || "").trim(),
          String(row?.time || "").trim(),
          normalizeCompanyName(row?.company).toLowerCase(),
          normalizeCompanyName(row?.place).toLowerCase()
        ].join("|");
      }

      function buildScheduleFallbackLooseKey(row) {
        return [
          String(row?.date || "").trim(),
          String(row?.time || "").trim(),
          normalizeCompanyName(row?.place).toLowerCase()
        ].join("|");
      }

      function collectStaleCleanupCandidates() {
        const canceledRows = readStorageArray(STORAGE_CANCELED_SCHEDULES);
        const canceledIdSet = new Set(
          canceledRows.map((row) => String(row?.customerScheduleId || "").trim()).filter(Boolean)
        );
        const canceledFallbackKeySet = new Set(canceledRows.map((row) => buildScheduleFallbackKey(row)));
        const canceledFallbackLooseKeySet = new Set(canceledRows.map((row) => buildScheduleFallbackLooseKey(row)));
        const candidates = [];
        const pushCandidate = (source, sourceLabel, row, index) => {
          const scheduleId = String(row?.customerScheduleId || "").trim();
          const strictKey = buildScheduleFallbackKey(row);
          const looseKey = buildScheduleFallbackLooseKey(row);
          const matched =
            (scheduleId && canceledIdSet.has(scheduleId)) ||
            canceledFallbackKeySet.has(strictKey) ||
            canceledFallbackLooseKeySet.has(looseKey);
          if (!matched) return;
          const candidateId = `${source}:${index}:${scheduleId || strictKey}`;
          candidates.push({
            candidateId,
            source,
            index,
            sourceLabel,
            scheduleId,
            date: String(row?.date || "").trim(),
            time: String(row?.time || "").trim(),
            company: normalizeCompanyName(row?.company),
            place: String(row?.place || "").trim()
          });
        };
        data.forEach((row, index) => pushCandidate("active", "м§„н–үмӨ‘", row, index));
        onHoldPayments.forEach((row, index) => pushCandidate("hold", "ліҙлҘҳ", row, index));
        refundPayments.forEach((row, index) => pushCandidate("refund", "нҷҳл¶Ҳ", row, index));
        const customerSchedules = readStorageArray(STORAGE_CUSTOMER_SCHEDULES);
        customerSchedules.forEach((row, index) => pushCandidate("customer", "кі к°қмҠӨмјҖмӨ„", row, index));
        return candidates;
      }

      function renderStaleCleanupModal(resetSelection = false) {
        staleCleanupCandidates = collectStaleCleanupCandidates();
        if (resetSelection) {
          staleCleanupSelectedIds = new Set(staleCleanupCandidates.map((item) => item.candidateId));
        } else {
          const validIdSet = new Set(staleCleanupCandidates.map((item) => item.candidateId));
          staleCleanupSelectedIds = new Set(
            [...staleCleanupSelectedIds].filter((candidateId) => validIdSet.has(candidateId))
          );
        }
        const counts = staleCleanupCandidates.reduce((acc, item) => {
          acc[item.source] = (acc[item.source] || 0) + 1;
          return acc;
        }, {});
        if (staleCleanupTitleEl) staleCleanupTitleEl.textContent = "кё°мЎҙ мһ”м—¬кұҙ м •лҰ¬";
        if (staleCleanupSummaryEl) {
          staleCleanupSummaryEl.innerHTML = `
            <div class="customer-stats-head">
              <span>мӮӯм ң нӣ„ліҙ мҙқ ${staleCleanupCandidates.length}кұҙ</span>
              <span>м§„н–үмӨ‘ ${counts.active || 0}кұҙ</span>
              <span>ліҙлҘҳ ${counts.hold || 0}кұҙ</span>
              <span>нҷҳл¶Ҳ ${counts.refund || 0}кұҙ</span>
              <span>кі к°қмҠӨмјҖмӨ„ ${counts.customer || 0}кұҙ</span>
              <button id="staleCleanupSelectAllBtn" class="btn-sm" type="button">м „мІҙм„ нғқ</button>
              <button id="staleCleanupSelectNoneBtn" class="btn-sm" type="button">м „мІҙн•ҙм ң</button>
            </div>
          `;
        }
        if (!staleCleanupListEl) return;
        if (!staleCleanupCandidates.length) {
          staleCleanupListEl.innerHTML = '<div class="company-item">нҳ„мһ¬ м •лҰ¬н•  кё°мЎҙ мһ”м—¬кұҙмқҙ м—ҶмҠөлӢҲлӢӨ.</div>';
          if (staleCleanupApplyBtnEl) staleCleanupApplyBtnEl.disabled = true;
          return;
        }
        if (staleCleanupApplyBtnEl) staleCleanupApplyBtnEl.disabled = false;
        staleCleanupListEl.innerHTML = staleCleanupCandidates
          .map((item) => {
            const checked = staleCleanupSelectedIds.has(item.candidateId) ? "checked" : "";
            const dateText = escapeHtml(item.date || "-");
            const timeText = escapeHtml(item.time || "-");
            const companyText = escapeHtml(item.company || "-");
            const placeText = escapeHtml(extractAreaLabel(item.place) || item.place || "-");
            return `
              <label class="customer-alert-row" style="align-items: flex-start; gap: 8px;">
                <input type="checkbox" data-candidate-id="${escapeHtml(item.candidateId)}" ${checked} />
                <span>[${escapeHtml(item.sourceLabel)}] ${dateText} ${timeText} / ${companyText} / ${placeText}</span>
              </label>
            `;
          })
          .join("");
      }

      function applySelectedStaleCleanup() {
        const selected = staleCleanupCandidates.filter((item) => staleCleanupSelectedIds.has(item.candidateId));
        if (!selected.length) {
          alert("мӮӯм ңн•  н•ӯлӘ©мқ„ м„ нғқн•ҙмЈјм„ёмҡ”.");
          return;
        }
        const makeMatcher = (source) => {
          const rows = selected.filter((item) => item.source === source);
          if (!rows.length) return () => false;
          const idSet = new Set(rows.map((item) => String(item.scheduleId || "").trim()).filter(Boolean));
          const strictSet = new Set(
            rows.map((item) =>
              [String(item.date || "").trim(), String(item.time || "").trim(), normalizeCompanyName(item.company).toLowerCase(), normalizeCompanyName(item.place).toLowerCase()].join("|")
            )
          );
          const looseSet = new Set(
            rows.map((item) => [String(item.date || "").trim(), String(item.time || "").trim(), normalizeCompanyName(item.place).toLowerCase()].join("|"))
          );
          return (row) => {
            const scheduleId = String(row?.customerScheduleId || "").trim();
            if (scheduleId && idSet.has(scheduleId)) return true;
            const strictKey = buildScheduleFallbackKey(row);
            if (strictSet.has(strictKey)) return true;
            const looseKey = buildScheduleFallbackLooseKey(row);
            return looseSet.has(looseKey);
          };
        };

        const activeMatcher = makeMatcher("active");
        const holdMatcher = makeMatcher("hold");
        const refundMatcher = makeMatcher("refund");
        const customerMatcher = makeMatcher("customer");

        for (let i = data.length - 1; i >= 0; i -= 1) {
          if (activeMatcher(data[i])) data.splice(i, 1);
        }
        for (let i = onHoldPayments.length - 1; i >= 0; i -= 1) {
          if (holdMatcher(onHoldPayments[i])) onHoldPayments.splice(i, 1);
        }
        for (let i = refundPayments.length - 1; i >= 0; i -= 1) {
          if (refundMatcher(refundPayments[i])) refundPayments.splice(i, 1);
        }
        const customerSchedules = readStorageArray(STORAGE_CUSTOMER_SCHEDULES);
        const nextCustomerSchedules = customerSchedules.filter((row) => !customerMatcher(row));
        localStorage.setItem(STORAGE_CUSTOMER_SCHEDULES, JSON.stringify(nextCustomerSchedules));

        staleCleanupModalEl?.classList.add("hidden");
        renderList();
        renderPaymentList();
        queueSchedulesSyncWithRetry(true);
        queuePaymentsSyncWithRetry();
        alert(`м„ нғқн•ң мһ”м—¬кұҙ ${selected.length}кұҙмқ„ м •лҰ¬н–ҲмҠөлӢҲлӢӨ.`);
      }

      function deletePreviousHistoryScheduleByPayload(payload) {
        const sourceLabel = String(payload?.sourceLabel || "м§„н–үмӨ‘").trim();
        const scheduleId = String(payload?.scheduleId || "").trim();
        const date = String(payload?.date || "").trim();
        const time = String(payload?.time || "").trim();
        const company = normalizeCompanyName(payload?.company);
        const place = String(payload?.place || "").trim();
        const targetList =
          sourceLabel === "ліҙлҘҳ" ? onHoldPayments : sourceLabel === "нҷҳл¶Ҳ" ? refundPayments : data;
        const targetIndex = targetList.findIndex((item) => {
          const sameById = scheduleId && String(item?.customerScheduleId || "").trim() === scheduleId;
          if (sameById) return true;
          return (
            String(item?.date || "").trim() === date &&
            String(item?.time || "").trim() === time &&
            normalizeCompanyName(item?.company) === company &&
            String(item?.place || "").trim() === place
          );
        });
        if (targetIndex < 0) {
          alert("н•ҙлӢ№ мқҙм „кё°лЎқмқ„ м°ҫм§Җ лӘ»н–ҲмҠөлӢҲлӢӨ.");
          return;
        }
        const targetItem = targetList[targetIndex];
        const shouldMoveToHoldAfterDelete =
          sourceLabel === "м§„н–үмӨ‘" && String(targetItem?.paymentStatus || "").trim() === "мһ…кёҲмҷ„лЈҢ";
        const confirmed = confirm("мқҙм „кё°лЎқ н•ӯлӘ©мқ„ мӮӯм ңн• к№Ңмҡ”?");
        if (!confirmed) return;
        appendCanceledScheduleRecord(targetItem, "admin", "мқҙм „кё°лЎқмӮӯм ң");
        targetList.splice(targetIndex, 1);
        if (shouldMoveToHoldAfterDelete) {
          const duplicateIndex = onHoldPayments.findIndex((row) => {
            const sameById =
              scheduleId && String(row?.customerScheduleId || "").trim() === String(scheduleId || "").trim();
            if (sameById) return true;
            return (
              String(row?.date || "").trim() === date &&
              String(row?.time || "").trim() === time &&
              normalizeCompanyName(row?.company) === company &&
              String(row?.place || "").trim() === place
            );
          });
          if (duplicateIndex >= 0) onHoldPayments.splice(duplicateIndex, 1);
          onHoldPayments.unshift({ ...targetItem });
        }

        const customerSchedules = readStorageArray(STORAGE_CUSTOMER_SCHEDULES);
        const customerIndex = customerSchedules.findIndex((row) => {
          const sameById = scheduleId && String(row?.customerScheduleId || "").trim() === scheduleId;
          if (sameById) return true;
          return (
            String(row?.date || "").trim() === date &&
            String(row?.time || "").trim() === time &&
            normalizeCompanyName(row?.company) === company &&
            String(row?.place || "").trim() === place
          );
        });
        if (customerIndex >= 0) {
          customerSchedules.splice(customerIndex, 1);
          localStorage.setItem(STORAGE_CUSTOMER_SCHEDULES, JSON.stringify(customerSchedules));
        }

        try {
          localStorage.setItem(STORAGE_ADMIN_SCHEDULES, JSON.stringify(data));
        } catch (_) {}
        syncWriterSchedulesStorage();
        if (scheduleId) {
          addPendingDeleteId(scheduleId);
          addScheduleDeleteTombstoneId(scheduleId);
          scheduleSyncCooldownUntil = Math.max(scheduleSyncCooldownUntil, Date.now() + 8000);
          void directPatchScheduleSource(scheduleId, "deleted");
          void deleteScheduleFromSupabaseByItem(targetItem);
        }

        renderPreviousScheduleHistory();
        renderList();
        renderPaymentList();
        queueSchedulesSyncWithRetry(true);
        queuePaymentsSyncWithRetry();
      }

      function handleScheduleListClick(event) {
        const button = event.target.closest("button[data-action]");
        if (!button) return;
        const action = button.dataset.action;
        const itemEl = button.closest("[data-schedule-card='true']") || button.closest(".item");
        const fallbackIndex = Number(itemEl?.dataset.index ?? button.dataset.index);
        const scheduleId = String(button.dataset.scheduleId || itemEl?.dataset.scheduleId || "").trim();
        const fallbackItem =
          !Number.isNaN(fallbackIndex) && fallbackIndex >= 0 && fallbackIndex < data.length ? data[fallbackIndex] : null;
        const fallbackMatchesScheduleId =
          Boolean(scheduleId) && fallbackItem && String(fallbackItem?.customerScheduleId || "").trim() === scheduleId;
        const scheduleIndex = scheduleId
          ? data.findIndex((row) => String(row?.customerScheduleId || "").trim() === scheduleId)
          : -1;
        const resolvedIndex = fallbackMatchesScheduleId
          ? fallbackIndex
          : scheduleIndex >= 0
          ? scheduleIndex
          : fallbackIndex;
        const index = resolvedIndex;
        const item = Number.isNaN(index) || index < 0 ? null : data[index];

        // мһ‘к°Җ мқҙлҰ„ мҳҶ гҖҢмҠӨмјҖмӨ„ ліөмӮ¬гҖҚ вҖ” index л¶Ҳн•„мҡ”(мһ‘к°ҖлӘ… кё°мӨҖ).
        if (action === "copyWriterSchedule") {
          void copyWriterScheduleListAdmin(button.dataset.writer || "");
          return;
        }

        if (action === "quickComposition" && !Number.isNaN(index) && item) {
          item.composition = item.composition === "мӮ¬м§„мҳҒмғҒ л‘ҳлӢӨ" ? "мӮ¬м§„л§Ң" : "мӮ¬м§„мҳҒмғҒ л‘ҳлӢӨ";
          markScheduleRowDirty(item, "schedule_mutation");
          syncCustomerScheduleFromAdminEdit(item, item.time || "");
          renderList();
          try { localStorage.setItem(STORAGE_ADMIN_SCHEDULES, JSON.stringify(data)); } catch (_) {}
          ensureScheduleUuid(item);
          syncWriterSchedulesStorage();
          queueSchedulesSyncWithRetry(true);
          void directPatchScheduleFields(item);
          return;
        }
        if (action === "setQuickComposition" && !Number.isNaN(index) && item) {
          const composition = String(button.dataset.composition || "").trim();
          if (!composition) return;
          item.composition = composition;
          markScheduleRowDirty(item, "schedule_mutation");
          syncCustomerScheduleFromAdminEdit(item, item.time || "");
          renderList();
          try { localStorage.setItem(STORAGE_ADMIN_SCHEDULES, JSON.stringify(data)); } catch (_) {}
          ensureScheduleUuid(item);
          syncWriterSchedulesStorage();
          queueSchedulesSyncWithRetry(true);
          void directPatchScheduleFields(item);
          return;
        }
        if (action === "startQuickPhotographer" && !Number.isNaN(index)) {
          quickPhotographerPickerIndex = index;
          renderList();
          return;
        }
        if (action === "cancelQuickPhotographer") {
          quickPhotographerPickerIndex = null;
          renderList();
          return;
        }
        if (action === "saveQuickPhotographer" && !Number.isNaN(index) && item) {
          const selected = itemEl?.querySelector(".quick-photographer-select")?.value;
          if (selected) {
            item.name = selected;
            item.writerPhone = photographerPhones[selected] || "";
            item.writerCarNumber = photographerCarNumbers[selected] || "";
            markScheduleRowDirty(item, "schedule_mutation");
            syncCustomerScheduleFromAdminEdit(item, item.time || "");
            try { localStorage.setItem(STORAGE_ADMIN_SCHEDULES, JSON.stringify(data)); } catch (_) {}
            ensureScheduleUuid(item);
            syncWriterSchedulesStorage();
            queueSchedulesSyncWithRetry(true);
            void directPatchScheduleFields(item);
          }
          quickPhotographerPickerIndex = null;
          renderList();
          return;
        }
        if (action === "setQuickWriter" && !Number.isNaN(index) && item) {
          const writerName = String(button.dataset.writerName || "").trim();
          if (!writerName) return;
          item.name = writerName;
          item.writerPhone = photographerPhones[writerName] || "";
          item.writerCarNumber = photographerCarNumbers[writerName] || "";
          markScheduleRowDirty(item, "schedule_mutation");
          syncCustomerScheduleFromAdminEdit(item, item.time || "");
          renderList();
          try { localStorage.setItem(STORAGE_ADMIN_SCHEDULES, JSON.stringify(data)); } catch (_) {}
          ensureScheduleUuid(item);
          syncWriterSchedulesStorage();
          queueSchedulesSyncWithRetry(true);
          void directPatchScheduleFields(item);
          return;
        }

        if (action === "startDateEdit" && !Number.isNaN(index)) {
          editingDateIndex = index;
          editingIndex = null;
          quickPhotographerPickerIndex = null;
          renderList();
          return;
        }
        if (action === "cancelDateEdit") {
          editingDateIndex = null;
          renderList();
          return;
        }
        if (action === "saveDateEdit" && !Number.isNaN(index)) {
          saveDateEdit(index, itemEl);
          return;
        }
        if (action === "deleteSchedule") {
          const sid = String(button.dataset.scheduleId || itemEl?.dataset.scheduleId || "").trim();
          if (sid && isUuidLike(sid)) {
            const byId = data.findIndex((row) => String(row?.customerScheduleId || "").trim() === sid);
            if (byId >= 0) {
              deleteSchedule(byId);
              return;
            }
          }
          if (!Number.isNaN(index) && index >= 0 && index < data.length) {
            deleteSchedule(index);
          }
          return;
        }
        if (action === "showMemo" && !Number.isNaN(index) && item) {
          const fullMemo = String(item.memo || "").trim();
          alert(fullMemo || "л“ұлЎқлҗң л©”лӘЁк°Җ м—ҶмҠөлӢҲлӢӨ.");
          return;
        }
        if (action === "showScheduleHistory" && !Number.isNaN(index) && item) {
          alert(getScheduleHistoryTimelineText(item));
          return;
        }

        if (action === "startEdit" && !Number.isNaN(index)) {
          editingIndex = index;
          editingDateIndex = null;
          quickPhotographerPickerIndex = null;
          renderList();
          return;
        }
        if (action === "cancelEdit") {
          editingIndex = null;
          renderList();
          return;
        }
        if (action === "saveEdit" && !Number.isNaN(index)) {
          saveInlineEdit(index, itemEl);
        }
      }
