      function submitScheduleFromForm(ignoreLimit = false) {
        const pickedDate = `${yearEl.value}-${monthEl.value.padStart(2, "0")}-${dayEl.value.padStart(2, "0")}`;
        const selectedTimePreference = normalizeTimePreference(scheduleTimePreferenceRegisterEl?.value);
        const pickedTime = scheduleTimeUndecided
          ? "мӢңк°„лҜём •"
          : selectedTimePreference === "other"
          ? "мғҒкҙҖм—ҶмқҢ"
          : `${String(scheduleHourRegisterEl?.value || "10").padStart(2, "0")}:${String(
              scheduleMinuteRegisterEl?.value || "00"
            ).padStart(2, "0")}`;
        const pickedTimePreference = scheduleTimeUndecided
          ? "exact"
          : selectedTimePreference;
        let pickedComposition = String(formEl.composition?.value || "").trim();
        const companyInputValue = document.getElementById("company").value || "";
        const normalizedCompany = normalizeCompanyName(companyInputValue);

        if (!isRegisteredCompanyName(normalizedCompany)) {
          alert("л“ұлЎқлҗң м—…мІҙл§Ң мҠӨмјҖмӨ„ л“ұлЎқн•  мҲҳ мһҲм–ҙмҡ”. лЁјм Җ м—…мІҙ л“ұлЎқм—җм„ң м¶”к°Җн•ҙмЈјм„ёмҡ”.");
          return;
        }
        // мҙ¬мҳҒкө¬м„ұ лҜём„ нғқмқҙл©ҙ, л“ұлЎқ м—…мІҙмқҳ кё°ліё мҙ¬мҳҒкө¬м„ұмңјлЎң мһҗлҸҷ ліҙм • нӣ„ м§„н–ү.
        // (м—…мІҙм •ліҙкҙҖлҰ¬м—җ кө¬м„ұмқҙ л“ұлЎқлҸј мһҲлҠ”лҚ° нҸјм—җм„ңл§Ң "лҜём„ нғқ"мқҙлқј л§үнһҲлҚҳ л¬ём ң н•ҙкІ°)
        if (!pickedComposition || !ADMIN_SUBMITTABLE_COMPOSITIONS.has(pickedComposition)) {
          const fallbackComp = getRegisteredCompanyDefaultCompositionByName(normalizedCompany);
          if (fallbackComp) {
            pickedComposition = fallbackComp;
            if (formEl.composition) formEl.composition.value = fallbackComp;
          }
        }
        if (!pickedComposition || !ADMIN_SUBMITTABLE_COMPOSITIONS.has(pickedComposition)) {
          alert("мҙ¬мҳҒ кө¬м„ұмқ„ лӘ©лЎқм—җм„ң м„ нғқн•ҙмЈјм„ёмҡ”.");
          return false;
        }
        const dailyLimit = getEffectiveDailyLimit(pickedDate);
        const countAtDate = getActiveScheduleCountByDate(pickedDate);
        if (!ignoreLimit && countAtDate >= dailyLimit) {
          alert("мҳҲм•Ҫмқҙ кҪүм°Ём„ң л“ұлЎқмқҙ м–ҙл өмҠөлӢҲлӢӨ. кҙҖлҰ¬мһҗм—җкІҢ л¬ёмқҳн•ҙмЈјм„ёмҡ”.");
          return false;
        }

        const canonicalIdentity = resolveCanonicalCompanyIdentity(normalizedCompany, "");
        const item = {
          customerScheduleId: buildClientUuid(),
          date: pickedDate || new Date().toISOString().slice(0, 10),
          time: pickedTime,
          timePreference: pickedTimePreference,
          requestedAt: new Date().toISOString(),
          localUpdatedAt: new Date().toISOString(),
          name: "мһ‘к°ҖлҜём •",
          writerPhone: "",
          writerCarNumber: "",
          company: canonicalIdentity.company || normalizedCompany,
          companyCode: canonicalIdentity.companyCode || "",
          place: document.getElementById("place").value || "-",
          pyeong: document.getElementById("pyeong").value || "",
          jointCode: document.getElementById("jointCode").value || "",
          doorCode: document.getElementById("doorCode").value || "",
          memo: document.getElementById("memo").value || "",
          composition: pickedComposition,
          paymentStatus: "лҜёмһ…кёҲ",
          paymentPayer: "",
          paymentAmount: "",
          paymentDate: "",
          couponUsed: false
        };

        data.unshift(item);
        const alerts = readStorageArray(STORAGE_CUSTOMER_ALERTS);
        alerts.unshift({
          id: `alert-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
          type: "schedule_create",
          scheduleId: String(item.customerScheduleId || "").trim(),
          company: item.company || "",
          date: item.date || "",
          time: item.time || "",
          createdAt: new Date().toISOString(),
          read: false
        });
        localStorage.setItem(STORAGE_CUSTOMER_ALERTS, JSON.stringify(alerts));
        const submissionReceipt = {
          receiptId: `rcpt-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
          scheduleId: String(item.customerScheduleId || "").trim(),
          customerId: "",
          company: String(item.company || "").trim(),
          date: String(item.date || "").trim(),
          time: String(item.time || "").trim(),
          timePreference: normalizeTimePreference(item.timePreference),
          place: String(item.place || "").trim(),
          source: "admin_create",
          createdAt: new Date().toISOString()
        };
        appendScheduleReceiptLedgerLocal(submissionReceipt);
        void appendScheduleReceiptLedgerToSupabase(submissionReceipt).catch((error) => {
          console.error("[SUBMISSION_RECEIPT][index] кҙҖлҰ¬мһҗ м ‘мҲҳкё°лЎқ м ҖмһҘ мӢӨнҢЁ", error);
        });
        formEl.reset();
        const now = new Date();
        yearEl.value = String(now.getFullYear());
        monthEl.value = String(now.getMonth() + 1);
        dayEl.value = String(now.getDate());
        if (scheduleHourRegisterEl) scheduleHourRegisterEl.value = "10";
        if (scheduleMinuteRegisterEl) scheduleMinuteRegisterEl.value = "00";
        if (scheduleTimePreferenceRegisterEl) scheduleTimePreferenceRegisterEl.value = "exact";
        setScheduleTimeUndecided(false);
        renderCustomerUpdateNotices();
        renderCustomerAlertHistory();
        if (USE_SUPABASE_SYNC) {
          queueSchedulesSync(true);
        }
        renderList();
        queuePaymentsSync();
        return true;
      }

      formEl.addEventListener("submit", (event) => {
        event.preventDefault();
        submitScheduleFromForm(false);
      });

      /** л“ұлЎқ м—…мІҙмқҳ кё°ліё мҙ¬мҳҒкө¬м„ұмқ„ л°ҳнҷҳ. м—…мІҙм •ліҙкҙҖлҰ¬ н‘ңмӢңмҷҖ лҸҷмқјн•ң мҡ°м„ мҲңмң„:
       *  мҮјн”Ҫ=м„ңл№„мҠӨн”Ңлһҳк·ё вҶ’ лӘ…мӢңм Ғ defaultComposition вҶ’ (л‘ҳ лӢӨ м—Ҷмңјл©ҙ) мӢңмҠӨн…ң кё°ліё "мӮ¬м§„л§Ң".
       *  л№ лҘё м—…мІҙл“ұлЎқмңјлЎң л§Ңл“  мқёлЎңк·ё м—…мІҙлҠ” defaultComposition мқҙ л№„м–ҙ мһҲмңјлҜҖлЎң,
       *  л§Ҳм§Җл§үм—җ "мӮ¬м§„л§Ң" мңјлЎң нҸҙл°ұн•ҙ мҠӨмјҖмӨ„ л“ұлЎқмқҙ л§үнһҲм§Җ м•ҠкІҢ н•ңлӢӨ.
       *  лҜёл“ұлЎқ м—…мІҙлӘ…мқҙл©ҙ "". */
      function getRegisteredCompanyDefaultCompositionByName(rawName) {
        const target = normalizeCompanyName(rawName).toLowerCase();
        if (!target) return "";
        const matched = (companies || []).find(
          (c) => normalizeCompanyName(c?.name).toLowerCase() === target
        );
        if (!matched) return "";
        // мҮјн”Ҫ м—…мІҙлҠ” м„ңл№„мҠӨ н”Ңлһҳк·ё(мӮ¬м§„/мҳҒмғҒ/лё”лЎңк·ё)м—җм„ң кө¬м„ұ лқјлІЁ лҸ„м¶ң
        if (normalizeCompanySiteTypeField(matched?.siteType) === "shopick") {
          try {
            const label = shopickFlagsToBaselineCompositionLabel(getShopickServiceFlagsFromCompanyRow(matched));
            if (ADMIN_SUBMITTABLE_COMPOSITIONS.has(label)) return label;
          } catch (_) {}
          return "мӮ¬м§„л§Ң";
        }
        const dc = String(matched?.defaultComposition || "").trim();
        if (ADMIN_SUBMITTABLE_COMPOSITIONS.has(dc)) return dc;
        // лӘ…мӢңм Ғ кё°ліёкө¬м„ұ лҜёл“ұлЎқ вҶ’ м•ұ м „м—ӯ кё°ліёк°’ "мӮ¬м§„л§Ң"
        return "мӮ¬м§„л§Ң";
      }

      /** мҠӨмјҖмӨ„ л“ұлЎқ нҸј: м—…мІҙлӘ…мқҙ л“ұлЎқ м—…мІҙмҷҖ мқјм№ҳн•ҳл©ҙ к·ё м—…мІҙмқҳ мҙ¬мҳҒкө¬м„ұмқ„ мһҗлҸҷ м„ нғқ.
       *  force=true(м—…мІҙ ліҖкІҪ мӢң) л©ҙ лҚ®м–ҙм“°кі , false л©ҙ м•„м§Ғ лҜём„ нғқмқј л•Ңл§Ң мұ„мҡҙлӢӨ. */
      function autofillScheduleCompositionFromCompany(force) {
        const sel = formEl?.composition;
        if (!sel) return;
        const companyName = document.getElementById("company")?.value || "";
        const dc = getRegisteredCompanyDefaultCompositionByName(companyName);
        if (!dc) return;
        const cur = String(sel.value || "").trim();
        if (!force && cur) return; // мҲҳлҸҷ м„ нғқк°’ ліҙмЎҙ
        const hasOption = Array.from(sel.options).some((o) => o.value === dc);
        if (hasOption) sel.value = dc;
      }

      const companyInputForScheduleEl = document.getElementById("company");
      // м—…мІҙлҘј кі лҘҙкұ°лӮҳ(datalist м„ нғқ) м—…мІҙлӘ… мһ…л Ҙмқ„ л§Ҳм№ҳл©ҙ к·ё м—…мІҙмқҳ кё°ліё мҙ¬мҳҒкө¬м„ұмқ„ мһҗлҸҷ мұ„мӣҖ.
      companyInputForScheduleEl?.addEventListener("change", () => autofillScheduleCompositionFromCompany(true));
      scheduleTimeUndecidedBtnEl?.addEventListener("click", () => {
        setScheduleTimeUndecided(!scheduleTimeUndecided);
      });
      scheduleTimeFlexibleBtnEl?.addEventListener("click", () => {
        if (scheduleTimeUndecided) setScheduleTimeUndecided(false);
        if (scheduleTimePreferenceRegisterEl) {
          scheduleTimePreferenceRegisterEl.value = "other";
        }
        setScheduleTimeUndecided(false);
      });
      scheduleHourRegisterEl?.addEventListener("change", () => {
        if (scheduleTimeUndecided) setScheduleTimeUndecided(false);
      });
      scheduleMinuteRegisterEl?.addEventListener("change", () => {
        if (scheduleTimeUndecided) setScheduleTimeUndecided(false);
      });
      scheduleTimePreferenceRegisterEl?.addEventListener("change", () => {
        setScheduleTimeUndecided(false);
      });

      adminOverrideSubmitBtnEl.addEventListener("click", () => {
        const password = String(adminOverridePasswordEl.value || "").trim();
        if (password !== ADMIN_OVERRIDE_PASSWORD) {
          alert("кҙҖлҰ¬мһҗ л№„л°ҖлІҲнҳёк°Җ мҳ¬л°”лҘҙм§Җ м•ҠмҠөлӢҲлӢӨ.");
          return;
        }
        const created = submitScheduleFromForm(true);
        if (!created) return;
        adminOverridePasswordEl.value = "";
      });

      // мһҗлҸҷ мҙҲкё°нҷ” л№„нҷңм„ұнҷ” (лҚ°мқҙн„° мң мӢӨ л°©м§Җ)
      async function bootstrapAdminPageData() {
        // мғҲлЎңкі м№Ё н”ҢлһҳмӢң л°©м§Җ: мІ« await(=мІ« paint) м „м—җ м ҖмһҘлҗң нғӯмқҳ н‘ңмӢң мғҒнғңлҘј лЁјм Җ м Ғмҡ©.
        // мқҙл ҮкІҢ н•ҳл©ҙ "мҠӨмјҖмӨ„лЎң мһ к№җ ліҙмҳҖлӢӨк°Җ м ҖмһҘлҗң нғӯмңјлЎң м җн”„"н•ҳлҚҳ к№ңл№Ўмһ„мқҙ мӮ¬лқјм§„лӢӨ.
        // (л ҢлҚ”лҠ” лҚ°мқҙн„° лЎңл“ң нӣ„ м•„лһҳ switchMainTab м—җм„ң мҲҳн–ү)
        try { applyAdminMainTabVisibility(getRestoredAdminMainTab()); } catch (_) {}
        // B-3: мІ« лҜјк°җ н…Ңмқҙлё” мқҪкё° м „м—җ кҙҖлҰ¬мһҗ нҶ нҒ° нҷ•ліҙ(м—Ҷмңјл©ҙ 1нҡҢ лЎңк·ёмқё).
        // м·ЁмҶҢн•ҳл©ҙ нҶ нҒ° "" вҶ’ кё°мЎҙ anon кІҪлЎңлЎң кі„мҶҚ лҸҷмһ‘(B-4 мһ кёҲ м „к№Ңм§Җ л¬ҙмӨ‘лӢЁ).
        try {
          await ensureAdminSessionToken(true);
        } catch (_) {}
        const clientKvPullDone = pullScheduleSiteClientKvFromSupabase();
        // лҢҖмӢңліҙл“ң GETкіј мҠӨмјҖмӨ„ GETмқ„ мҲңм°Ё(await)н•ҳм§Җ м•ҠмқҢ вҖ” мҙҲкё° мІҙк°җ м§Җм—°(н•©мӮ° мӢңк°„) л°©м§Җ
        const dashboardBootstrapPromise =
          USE_SUPABASE_SYNC
            ? fetchDashboardStateWithRetriesForBootstrap().catch((e) => {
                console.warn("[DASHBOARD_STATE] bootstrap", e);
              })
            : Promise.resolve();
        if (!USE_SUPABASE_SYNC) {
          loadDashboardPanelsFromNativeLocalStorageIfNoSupabase();
        }
        loadAdminCompaniesFromStorage();
        void pullAdminCompaniesFromSupabaseAndRefresh();
        void pullCustomersFromSupabaseAndApply().then(() => {
          renderCustomerStatsDashboard();
          renderCompanies();
        });
        loadCouponPassesFromStorage();
        mergeCouponPassesByCanonicalIdentity();
        void pullCouponPassesFromSupabaseAndApply().then((changed) => {
          mergeCouponPassesByCanonicalIdentity();
          if (changed) {
            renderCouponPassList();
            renderPaymentList();
          }
        });
        restorePendingDeleteIdsFromStorage(); // loadAdminSchedulesFromStorage м „м—җ ліөмӣҗн•ҙм•ј н•„н„°л§Ғ м Ғмҡ©лҗЁ
        loadAdminSchedulesFromStorage();
        // мқҙм „ м„ём…ҳм—җм„ң PATCH мӢӨнҢЁн•ң н•ӯлӘ©мқ„ л°ұк·ёлқјмҡҙл“ңм—җм„ң мһ¬мӢңлҸ„ (source="deleted" мҳҒкө¬ м„Өм •)
        setTimeout(() => resumePendingDeletePatches(), 3000);
        initializeScheduleReceiptLedgerStorage();
        await Promise.all([dashboardBootstrapPromise, pullSchedulesFromSupabaseAndApply()]);
        void pullDayoffRequestsFromSupabaseAndApply();
        void pullSubmissionReceiptsFromSupabaseAndApply();
        void pullSharedLimitConfigAndApply();
        void pullSharedMasterAccountMapAndApply();
        void pullBlogSendLogFromSupabaseAndApply().then(() => {
          try { if (typeof renderBlogTaskList === "function") renderBlogTaskList(); } catch (_) {}
        });
        hydrateFromCustomerPageStorage();
        bootstrapMasterAccountsForExistingCompanies();
        bootstrapMasterAccountsFromCurrentCustomersV2();
        bootstrapMasterCompaniesFromRegisteredCompaniesV3();
        loadPhotographerProfilesFromStorage();
        void pullWritersFromSupabaseAndRefresh();
        void pullPaymentsFromSupabaseAndApply();
        hydrateFromWriterPageStorage();
        renderPhotographers();
        renderCustomerStatsDashboard();
        renderCustomerUpdateNotices();
        renderCustomerAlertHistory();
        updateFullBackupInfoText();
        renderCompanies();
        setupDateInputs();
        setupCouponInputs();
        setupScheduleFilters();
        renderList();
        // мғҲлЎңкі м№Ё мӢң ліҙлҚҳ нғӯ к·ёлҢҖлЎң ліөмӣҗ вҖ” лҚ°мқҙн„°В·м…Ӣм—… мҷ„лЈҢ нӣ„ мӢӨм ң л ҢлҚ”к№Ңм§Җ мҲҳн–ү.
        // (н‘ңмӢң нҶ кёҖмқҖ мң„ bootstrap мҙҲл°ҳм—җм„ң мқҙлҜё м„ м Ғмҡ©н•ҙ н”ҢлһҳмӢң м—ҶмқҢ)
        switchMainTab(getRestoredAdminMainTab());
        clientKvPullDone.then((didHydrate) => {
          // didHydrate=false лқјлҸ„ (мІ« pull мӢӨнҢЁВ·м„ңлІ„ л№Ҳ мқ‘лӢөВ·snapshot л§Ң мһҲмқ„ л•Ң) JS л°°м—ҙмқҖ
          // memoryStore мҷҖ мқјм№ҳмӢңмјңм•ј н•ңлӢӨ. мҳҲм „м—” м—¬кё°м„ң early-return н•ҙм„ң, pull мқҙ н•ң лІҲ
          // мӢӨнҢЁн•ҳл©ҙ мһ‘к°Җ/нҡҢмӮ¬/мҠӨмјҖмӨ„ л°°м—ҙмқҙ мҳҒкө¬ л№Ҳ мғҒнғңлЎң лӮЁкі  нҺҳмқҙм§Җк°Җ н…… л№„м–ҙ ліҙмқҙлҚҳ лІ„к·ё.
          loadAdminCompaniesFromStorage();
          // USE_SUPABASE_SYNC лӘЁл“ңм—җм„ңлҠ” schedules н…Ңмқҙлё” pullмқҙ dataлҘј лҚ®м–ҙм“°лҜҖлЎң
          // м„ңлІ„ KVм—җ лӮЁм•„мһҲлҠ” кө¬лІ„м „ scheduleSiteAdminSchedulesлЎң dataлҘј лҚ®м–ҙм“°м§Җ м•ҠлҸ„лЎқ skip
          if (!USE_SUPABASE_SYNC) loadAdminSchedulesFromStorage();
          loadCouponPassesFromStorage();
          mergeCouponPassesByCanonicalIdentity();
          hydrateFromCustomerPageStorage();
          hydrateFromWriterPageStorage();
          loadPhotographerProfilesFromStorage();
          bootstrapMasterAccountsForExistingCompanies();
          bootstrapMasterAccountsFromCurrentCustomersV2();
          bootstrapMasterCompaniesFromRegisteredCompaniesV3();
          renderPhotographers();
          renderCompanies();
          renderCustomerStatsDashboard();
          renderCustomerUpdateNotices();
          renderCustomerAlertHistory();
          renderList();
          renderPaymentList();
          // мһ‘к°Җ кёүм—¬ нғӯмқҙ мқҙлҜё м—ҙл Ө мһҲмқ„ мҲҳ мһҲмңјлҜҖлЎң м„ңлІ„ KV pull нӣ„м—җлҸ„ мһ¬л ҢлҚ”л§Ғ.
          // лӢӨлҘё лёҢлқјмҡ°м Җм—җм„ң м ҖмһҘн•ң мң лҘҳл№„В·кёүм—¬нҳ•нғңк°Җ мҰүмӢң л°ҳмҳҒлҗҳлҸ„лЎқ н•ңлӢӨ.
          if (typeof renderPhotographerPayrollAdmin === "function") {
            try { renderPhotographerPayrollAdmin(); } catch (_) {}
          }
        });
        startDashboardStateBackgroundSync();
      }
      void bootstrapAdminPageData().catch((e) => console.error("[BOOT]", e));

      // blog_send_log лҠ” лӢӨмӨ‘ лёҢлқјмҡ°м Җ лҸҷкё°нҷ”к°Җ мһҰмқҖ нӮӨлқј focusВ·visibility мӢң л§ӨлІҲ pull.
      function refreshBlogSendLogOnFocus() {
        void pullBlogSendLogFromSupabaseAndApply().then(() => {
          try { if (typeof renderBlogTaskList === "function") renderBlogTaskList(); } catch (_) {}
        });
      }
      window.addEventListener("focus", () => {
        scheduleSoftPullClientKvFromSupabase();
        refreshBlogSendLogOnFocus();
      });
      document.addEventListener("visibilitychange", () => {
        if (document.visibilityState !== "visible") return;
        scheduleSoftPullClientKvFromSupabase();
        refreshBlogSendLogOnFocus();
      });
      window.addEventListener("online", () => {
        scheduleSoftPullClientKvFromSupabase();
        refreshBlogSendLogOnFocus();
      });

      window.addEventListener("storage", (event) => {
        if (event.key === "__scheduleSiteSnapshotV1") {
          scheduleSoftPullClientKvFromSupabase();
        }
        if (event.key === STORAGE_CANCELED_SCHEDULES) {
          renderCanceledSchedules();
        }
        if (event.key === STORAGE_ADMIN_COMPANIES) {
          loadAdminCompaniesFromStorage();
          renderCompanies();
        }
        if (event.key === STORAGE_ADMIN_SCHEDULES) {
          if (USE_SUPABASE_SYNC) {
            if (storagePullSchedulesDebounceTimer) clearTimeout(storagePullSchedulesDebounceTimer);
            storagePullSchedulesDebounceTimer = setTimeout(() => {
              storagePullSchedulesDebounceTimer = null;
              void pullSchedulesFromSupabaseAndApply();
            }, 450);
          } else {
            loadAdminSchedulesFromStorage();
            renderList();
          }
        }
        if (event.key === STORAGE_CUSTOMER_SCHEDULES || event.key === STORAGE_CUSTOMER_COMPANIES) {
          hydrateFromCustomerPageStorage();
          renderCustomerStatsDashboard();
          renderCompanies();
          renderList();
        }
        if (
          event.key === STORAGE_WRITERS ||
          event.key === STORAGE_EXCLUDED_PHOTOGRAPHERS ||
          event.key === STORAGE_PHOTOGRAPHER_PROFILES
        ) {
          loadPhotographerProfilesFromStorage();
          hydrateFromWriterPageStorage();
          renderPhotographers();
          renderList();
        }
        if (event.key === STORAGE_PHOTOGRAPHER_PAYROLL_CONFIG || event.key === STORAGE_PHOTOGRAPHER_PAYROLL_MONTHLY) {
          renderPhotographerPayrollAdmin();
        }
        if (
          event.key === STORAGE_CUSTOMER_ALERTS ||
          event.key === STORAGE_CUSTOMER_SUBMISSION_LOGS ||
          event.key === STORAGE_SUBMISSION_RECEIPT_READ_IDS
        ) {
          renderCustomerUpdateNotices();
          renderCustomerAlertHistory();
        }
        if (event.key === STORAGE_SCHEDULE_RECEIPT_LEDGER) {
          renderScheduleReceiptLedger();
        }
        if (event.key === STORAGE_THEFEELING_EDIT_REQUESTS || event.key === STORAGE_THEFEELING_EDIT_REQUESTS_ARCHIVE) {
          if (!thefeelingEditSectionEl?.classList.contains("hidden")) {
            renderThefeelingEditRequests();
          }
        }
        if (event.key === STORAGE_CUSTOMERS || event.key === STORAGE_CUSTOMER_LOGINS) {
          renderCustomerStatsDashboard();
          renderCompanies();
        }
        if (event.key === STORAGE_MASTER_ACCOUNT_MAP) {
          renderCompanies();
          if (companyOrderHistoryModalEl && !companyOrderHistoryModalEl.classList.contains("hidden")) {
            const modalTitle = String(companyOrderHistoryTitleEl.textContent || "").replace(/\s*мЈјл¬ё кё°лЎқ$/, "");
            if (modalTitle) renderCompanyOrderHistory(modalTitle);
          }
        }
        if (
          event.key === STORAGE_DAILY_LIMITS ||
          event.key === STORAGE_EMERGENCY_LIMIT_ADDITIONS ||
          event.key === STORAGE_LIMIT_CONFIG ||
          event.key === STORAGE_DAYOFF_DEDUCTIONS ||
          event.key === STORAGE_DAYOFF_REQUESTS ||
          event.key === STORAGE_DAYOFF_ALERT_READ_IDS
        ) {
          renderScheduleCalendar();
          renderOpenDayoffSummary();
          renderCustomerUpdateNotices();
          renderCustomerAlertHistory();
        }
      });

      window.addEventListener("focus", () => {
        loadAdminCompaniesFromStorage();
        void pullCustomersFromSupabaseAndApply().then(() => {
          renderCustomerStatsDashboard();
          renderCompanies();
        });
        loadCouponPassesFromStorage();
        mergeCouponPassesByCanonicalIdentity();
        void pullCouponPassesFromSupabaseAndApply().then((changed) => {
          mergeCouponPassesByCanonicalIdentity();
          if (changed) {
            renderCouponPassList();
            renderPaymentList();
          }
        });
        void pullDayoffRequestsFromSupabaseAndApply();
        void pullSubmissionReceiptsFromSupabaseAndApply();
        void pullSharedMasterAccountMapAndApply();
        const finishFocusUiAfterSchedulePull = () => {
          hydrateFromCustomerPageStorage();
          bootstrapMasterAccountsForExistingCompanies();
          bootstrapMasterAccountsFromCurrentCustomersV2();
          bootstrapMasterCompaniesFromRegisteredCompaniesV3();
          loadPhotographerProfilesFromStorage();
          hydrateFromWriterPageStorage();
          renderPhotographers();
          renderCustomerStatsDashboard();
          renderCustomerUpdateNotices();
          renderCustomerAlertHistory();
          renderCompanies();
          renderList();
        };
        if (USE_SUPABASE_SYNC) {
          restorePendingDeleteIdsFromStorage();
          void fetchAndApplyDashboardStateFromSupabase().then(() => renderList());
          void pullSchedulesFromSupabaseAndApply().then(() => {
            finishFocusUiAfterSchedulePull();
          });
        } else {
          loadAdminSchedulesFromStorage();
          finishFocusUiAfterSchedulePull();
        }
      });

      document.addEventListener("visibilitychange", () => {
        if (document.visibilityState === "hidden" && USE_SUPABASE_SYNC) {
          if (dashboardStateSaveTimer !== null) {
            clearTimeout(dashboardStateSaveTimer);
            dashboardStateSaveTimer = null;
          }
          if (isDashboardStatePendingServerSync() && !isApplyingRemoteDashboardState) {
            void saveDashboardPanelsStateToSupabase();
          }
        }
        if (document.visibilityState !== "visible") return;
        loadAdminCompaniesFromStorage();
        void pullCustomersFromSupabaseAndApply().then(() => {
          renderCustomerStatsDashboard();
          renderCompanies();
        });
        loadCouponPassesFromStorage();
        mergeCouponPassesByCanonicalIdentity();
        void pullCouponPassesFromSupabaseAndApply().then((changed) => {
          mergeCouponPassesByCanonicalIdentity();
          if (changed) {
            renderCouponPassList();
            renderPaymentList();
          }
        });
        void pullDayoffRequestsFromSupabaseAndApply();
        void pullSubmissionReceiptsFromSupabaseAndApply();
        void pullSharedMasterAccountMapAndApply();
        const finishVisibilityUiAfterSchedulePull = () => {
          hydrateFromCustomerPageStorage();
          bootstrapMasterAccountsForExistingCompanies();
          bootstrapMasterAccountsFromCurrentCustomersV2();
          bootstrapMasterCompaniesFromRegisteredCompaniesV3();
          loadPhotographerProfilesFromStorage();
          hydrateFromWriterPageStorage();
          renderPhotographers();
          renderCustomerStatsDashboard();
          renderCustomerUpdateNotices();
          renderCustomerAlertHistory();
          renderOpenDayoffSummary();
          renderCanceledSchedules();
          renderList();
        };
        if (USE_SUPABASE_SYNC) {
          restorePendingDeleteIdsFromStorage();
          void fetchAndApplyDashboardStateFromSupabase().then(() => renderList());
          void pullSchedulesFromSupabaseAndApply().then(() => {
            finishVisibilityUiAfterSchedulePull();
          });
        } else {
          loadAdminSchedulesFromStorage();
          finishVisibilityUiAfterSchedulePull();
        }
      });
